import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Message {
  id: string;
  role: 'user' | 'assistant' | 'system';
  text: string;
  timestamp: Date;
}

export enum ConnectionState {
  DISCONNECTED = 'DISCONNECTED',
  CONNECTING = 'CONNECTING',
  CONNECTED = 'CONNECTED',
  ERROR = 'ERROR',
}

export interface SystemStatus {
  cpu: number;
  ram: number;
  battery: number;
}

export interface Reminder {
  title: string;
  time: string;
}

// Tool definitions for TypeScript
export interface ToolCallArgs {
  [key: string]: any;
}

import { Blob } from "@google/genai";

export function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function arrayBufferToBase64(buffer: ArrayBuffer): string {
  let binary = '';
  const bytes = new Uint8Array(buffer);
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function createPcmBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    // Clamp values to [-1, 1] range to prevent clipping/distortion
    const s = Math.max(-1, Math.min(1, data[i]));
    // Convert float32 to int16 PCM
    int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
  }
  return {
    data: arrayBufferToBase64(int16.buffer),
    mimeType: 'audio/pcm;rate=16000',
  };
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import { useState, useRef, useEffect, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";
import { SYSTEM_INSTRUCTION, tools } from '../constants';
import { createPcmBlob, decodeAudioData, base64ToUint8Array } from '../utils/audio';
import { ConnectionState, Message } from '../types';

interface UseLiveSessionProps {
  onToolCall?: (name: string, args: any) => Promise<any>;
}

export const useLiveSession = ({ onToolCall }: UseLiveSessionProps) => {
  const [connectionState, setConnectionState] = useState<ConnectionState>(ConnectionState.DISCONNECTED);
  const [transcripts, setTranscripts] = useState<Message[]>([]);
  const [volume, setVolume] = useState<number>(0);

  // Refs for audio handling and session management
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const inputSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const analyserRef = useRef<AnalyserNode | null>(null);

  // Helper to append transcripts
  const addTranscript = useCallback((role: 'user' | 'assistant' | 'system', text: string) => {
    setTranscripts(prev => [
      ...prev,
      { id: Date.now().toString() + Math.random(), role, text, timestamp: new Date() }
    ]);
  }, []);

  const connect = useCallback(async () => {
    if (!process.env.API_KEY) {
      addTranscript('system', 'Error: API Key is missing.');
      setConnectionState(ConnectionState.ERROR);
      return;
    }

    try {
      setConnectionState(ConnectionState.CONNECTING);

      // Initialize Audio Contexts
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      inputContextRef.current = inputCtx;
      outputContextRef.current = outputCtx;

      // Audio Analyser for visualization
      const analyser = outputCtx.createAnalyser();
      analyser.fftSize = 256;
      analyserRef.current = analyser;

      // Setup Input Stream
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const source = inputCtx.createMediaStreamSource(stream);
      inputSourceRef.current = source;

      // Setup Processor (Deprecated but functional for standard raw PCM processing in browser)
      const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
      processorRef.current = scriptProcessor;

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: SYSTEM_INSTRUCTION,
          tools: [{ functionDeclarations: tools }],
          inputAudioTranscription: { model: "gemini-2.5-flash-native-audio-preview-09-2025" }, 
        },
        callbacks: {
          onopen: () => {
            console.log('Session connected');
            setConnectionState(ConnectionState.CONNECTED);
            addTranscript('system', 'Voice Assistant Connected. Start speaking...');

            // Connect Audio Nodes
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              // Calculate volume for visualization (input side)
              let sum = 0;
              for (let i = 0; i < inputData.length; i++) {
                 sum += inputData[i] * inputData[i];
              }
              const rms = Math.sqrt(sum / inputData.length);
              setVolume(v => (v * 0.8) + (rms * 2)); // Smooth update

              const pcmBlob = createPcmBlob(inputData);
              if (sessionPromiseRef.current) {
                sessionPromiseRef.current.then(session => {
                    session.sendRealtimeInput({ media: pcmBlob });
                });
              }
            };
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Audio Output
            const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData) {
              const ctx = outputContextRef.current;
              if (ctx) {
                 // Sync timing
                 nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                 const audioBuffer = await decodeAudioData(
                   base64ToUint8Array(audioData),
                   ctx,
                   24000,
                   1
                 );

                 const source = ctx.createBufferSource();
                 source.buffer = audioBuffer;

                 // Connect to analyser for output visualization
                 if (analyserRef.current) {
                    source.connect(analyserRef.current);
                    analyserRef.current.connect(ctx.destination);
                 } else {
                    source.connect(ctx.destination);
                 }

                 source.addEventListener('ended', () => {
                    audioSourcesRef.current.delete(source);
                 });

                 source.start(nextStartTimeRef.current);
                 audioSourcesRef.current.add(source);
                 nextStartTimeRef.current += audioBuffer.duration;
              }
            }

            // Handle Transcripts
            if (message.serverContent?.turnComplete) {
               // Usually handled by intermediate updates, but good for final checks
            }

            // Note: The Live API is currently preview and transcription formats vary.
            // We check for input/output transcriptions if available in serverContent
            // In the provided doc example, it shows `outputTranscription` and `inputTranscription`.

            // Check Input Transcription (User)
            const inputTranscript = (message.serverContent as any)?.inputTranscription?.text;
            if (inputTranscript) {
               // For streaming text, we might want to update the last user message instead of appending new ones constantly
               // But for simplicity, we'll just log complete turns or rely on the UI to debounce
               // We will filter out empty strings
               // Implementation Note: The current API often sends partials. We'll simplify by just ignoring here and relying on "turnComplete" if we wanted strict chat logs.
               // For this demo, we won't flood the UI with partials.
            }

            // Check Output Transcription (Model)
            const outputTranscript = (message.serverContent as any)?.outputTranscription?.text;
             if (outputTranscript) {
                 // Same as above
             }

            // Handle Tool Calls
            if (message.toolCall) {
                addTranscript('system', 'Executing assistant tools...');
                for (const fc of message.toolCall.functionCalls) {
                    console.log('Tool Call:', fc.name, fc.args);
                    let result = { result: 'Success' };

                    if (onToolCall) {
                       try {
                           const output = await onToolCall(fc.name, fc.args);
                           result = output;
                           addTranscript('system', `Tool executed: ${fc.name}`);
                       } catch (e) {
                           console.error('Tool execution failed', e);
                           result = { error: 'Failed to execute tool' };
                       }
                    }

                    if (sessionPromiseRef.current) {
                        sessionPromiseRef.current.then(session => {
                            session.sendToolResponse({
                                functionResponses: {
                                    id: fc.id,
                                    name: fc.name,
                                    response: result
                                }
                            });
                        });
                    }
                }
            }
          },
          onclose: () => {
            console.log('Session closed');
            setConnectionState(ConnectionState.DISCONNECTED);
            addTranscript('system', 'Session ended.');
          },
          onerror: (err) => {
            console.error('Session error:', err);
            setConnectionState(ConnectionState.ERROR);
            addTranscript('system', 'Connection error occurred.');
          }
        }
      });

      sessionPromiseRef.current = sessionPromise;

    } catch (error) {
      console.error('Connection failed:', error);
      setConnectionState(ConnectionState.ERROR);
    }
  }, [addTranscript, onToolCall]);

  const disconnect = useCallback(async () => {
    if (sessionPromiseRef.current) {
       const session = await sessionPromiseRef.current;
       // There is no explicit close() method on the session object in the provided snippet?
       // The example says `session.close()` in "Live API Rules", but the snippet doesn't show it on the returned object from live.connect.
       // However, we can close the audio contexts and let the socket timeout/close from the server or client side logic.
       // If the SDK supports it: session.close(); 
       // Assuming it does based on standard socket wrappers.
       try {
         (session as any).close();
       } catch (e) { console.warn('Could not close session explicitly', e)}
    }

    // Cleanup Audio
    if (inputContextRef.current) inputContextRef.current.close();
    if (outputContextRef.current) outputContextRef.current.close();
    if (processorRef.current) processorRef.current.disconnect();
    if (inputSourceRef.current) inputSourceRef.current.disconnect();

    // Stop all playing sources
    audioSourcesRef.current.forEach(source => source.stop());
    audioSourcesRef.current.clear();

    setConnectionState(ConnectionState.DISCONNECTED);
    setVolume(0);
    sessionPromiseRef.current = null;
  }, []);

  // Update volume from analyser for output audio visualization
  useEffect(() => {
    let animationFrame: number;
    const updateOutputVolume = () => {
        if (analyserRef.current) {
            const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
            analyserRef.current.getByteFrequencyData(dataArray);
            let sum = 0;
            for(let i=0; i<dataArray.length; i++) {
                sum += dataArray[i];
            }
            const avg = sum / dataArray.length;
            // Normalize somewhat
            const norm = avg / 255; 
            // We want to combine input volume and output volume for a single "Activity" visualizer
            // But usually, only one happens at a time.
            if (norm > 0.01) {
                setVolume(prev => (prev * 0.5) + (norm * 0.5));
            }
        }
        animationFrame = requestAnimationFrame(updateOutputVolume);
    };
    updateOutputVolume();
    return () => cancelAnimationFrame(animationFrame);
  }, []);

  return {
    connect,
    disconnect,
    connectionState,
    transcripts,
    volume
  };
};

import React, { useEffect, useRef } from 'react';

interface VisualizerProps {
  volume: number;
  active: boolean;
}

const Visualizer: React.FC<VisualizerProps> = ({ volume, active }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrame: number;

    // Config
    const centerX = canvas.width / 2;
    const centerY = canvas.height / 2;
    const baseRadius = 60;

    // Animation state
    let rotation = 0;

    const render = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Dynamic radius based on volume
      // volume is roughly 0 to 1
      const dynamicRadius = baseRadius + (volume * 100);

      // Draw Glow
      const gradient = ctx.createRadialGradient(centerX, centerY, baseRadius * 0.5, centerX, centerY, dynamicRadius * 1.5);

      if (active) {
          gradient.addColorStop(0, 'rgba(59, 130, 246, 0.8)'); // Blue core
          gradient.addColorStop(0.5, 'rgba(147, 51, 234, 0.3)'); // Purple mid
          gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
      } else {
          gradient.addColorStop(0, 'rgba(113, 113, 122, 0.5)'); // Gray core
          gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
      }

      ctx.fillStyle = gradient;
      ctx.beginPath();
      ctx.arc(centerX, centerY, dynamicRadius * 1.5, 0, Math.PI * 2);
      ctx.fill();

      // Draw Core Orb
      ctx.beginPath();
      ctx.arc(centerX, centerY, active ? baseRadius + (volume * 20) : baseRadius, 0, Math.PI * 2);
      ctx.strokeStyle = active ? '#60a5fa' : '#52525b';
      ctx.lineWidth = 2;
      ctx.stroke();

      // Draw Orbiting Particles (Developer mode sci-fi feel)
      if (active) {
        rotation += 0.02;
        const numParticles = 3;
        for(let i=0; i<numParticles; i++) {
            const angle = rotation + (i * (Math.PI * 2 / numParticles));
            const orbitR = dynamicRadius * 0.8;
            const px = centerX + Math.cos(angle) * orbitR;
            const py = centerY + Math.sin(angle) * orbitR;

            ctx.beginPath();
            ctx.arc(px, py, 4, 0, Math.PI * 2);
            ctx.fillStyle = '#ffffff';
            ctx.fill();
        }
      }

      animationFrame = requestAnimationFrame(render);
    };

    render();

    return () => cancelAnimationFrame(animationFrame);
  }, [volume, active]);

  return (
    <canvas 
      ref={canvasRef} 
      width={400} 
      height={400} 
      className="w-full max-w-[300px] h-auto mx-auto"
    />
  );
};

export default Visualizer;

import React, { useEffect, useRef } from 'react';
import { Message } from '../types';
import { Terminal, Bot, User } from 'lucide-react';

interface ChatInterfaceProps {
  messages: Message[];
}

const ChatInterface: React.FC<ChatInterfaceProps> = ({ messages }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  return (
    <div className="flex-1 bg-zinc-900/50 rounded-xl border border-zinc-800 p-4 flex flex-col h-full overflow-hidden">
      <div className="flex items-center gap-2 pb-4 border-b border-zinc-800 mb-4">
        <Terminal className="w-5 h-5 text-indigo-400" />
        <h2 className="text-sm font-semibold text-zinc-300 tracking-wider">SYSTEM LOGS</h2>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto space-y-4 pr-2">
        {messages.length === 0 && (
          <div className="text-zinc-500 text-sm text-center italic mt-10">
            Waiting for input stream...
          </div>
        )}
        {messages.map((msg) => (
          <div key={msg.id} className={`flex gap-3 ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            {msg.role !== 'user' && (
              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${msg.role === 'system' ? 'bg-yellow-500/10 text-yellow-500' : 'bg-indigo-500/10 text-indigo-400'}`}>
                {msg.role === 'system' ? <Terminal size={14} /> : <Bot size={16} />}
              </div>
            )}

            <div className={`max-w-[80%] p-3 rounded-lg text-sm ${
              msg.role === 'user' 
                ? 'bg-zinc-800 text-zinc-200 rounded-br-none' 
                : msg.role === 'system'
                ? 'bg-transparent text-yellow-500/80 font-mono text-xs'
                : 'bg-zinc-800/50 text-zinc-300 rounded-bl-none border border-zinc-700/50'
            }`}>
              {msg.text}
            </div>

            {msg.role === 'user' && (
              <div className="w-8 h-8 rounded-full bg-zinc-700 flex items-center justify-center shrink-0">
                <User size={16} className="text-zinc-400" />
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default ChatInterface;

import React, { useState, useCallback, useEffect } from 'react';
import { Mic, MicOff, Settings, Activity } from 'lucide-react';
import { useLiveSession } from './hooks/useLiveSession';
import Visualizer from './components/Visualizer';
import ChatInterface from './components/ChatInterface';
import InfoPanel from './components/InfoPanel';
import { ConnectionState, SystemStatus } from './types';

function App() {
  const [devMode, setDevMode] = useState(false);
  const [systemStatus, setSystemStatus] = useState<SystemStatus>({
    cpu: 12,
    ram: 6.4,
    battery: 85
  });

  // Simulate system activity
  useEffect(() => {
    const interval = setInterval(() => {
      setSystemStatus(prev => ({
        cpu: Math.min(100, Math.max(5, prev.cpu + (Math.random() * 10 - 5))),
        ram: prev.ram, // Static ram for stability
        battery: Math.max(0, prev.battery - 0.01)
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  const handleToolCall = useCallback(async (name: string, args: any) => {
    if (name === 'getSystemStatus') {
      return { 
        cpu: `${Math.round(systemStatus.cpu)}%`,
        ram: `${systemStatus.ram} GB`,
        battery: `${Math.round(systemStatus.battery)}%`,
        status: 'Operational'
      };
    }

    if (name === 'setReminder') {
      // In a real app, this would save to localStorage or backend
      return { 
        success: true, 
        message: `Reminder set for ${args.task} at ${args.time}` 
      };
    }

    if (name === 'toggleDeveloperMode') {
      const enabled = args.enabled;
      setDevMode(enabled);
      return {
        success: true,
        mode: enabled ? 'Developer Mode Enabled' : 'Standard Mode Enabled',
        info: enabled ? 'Verbose logging active. Technical details prioritized.' : 'Standard assistance active.'
      };
    }

    return { error: 'Unknown tool' };
  }, [systemStatus]);

  const { connect, disconnect, connectionState, transcripts, volume } = useLiveSession({
    onToolCall: handleToolCall
  });

  const isConnected = connectionState === ConnectionState.CONNECTED;
  const isConnecting = connectionState === ConnectionState.CONNECTING;

  const toggleConnection = () => {
    if (isConnected || isConnecting) {
      disconnect();
    } else {
      connect();
    }
  };

  return (
    <div className="min-h-screen bg-zinc-950 text-zinc-100 flex flex-col items-center justify-center p-4 md:p-8 relative overflow-hidden">

      {/* Background Ambience */}
      <div className="absolute top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0">
        <div className={`absolute top-[-20%] left-[-10%] w-[50%] h-[50%] bg-blue-900/20 rounded-full blur-[100px] transition-all duration-1000 ${isConnected ? 'opacity-100' : 'opacity-30'}`}></div>
        <div className={`absolute bottom-[-20%] right-[-10%] w-[50%] h-[50%] bg-purple-900/20 rounded-full blur-[100px] transition-all duration-1000 ${isConnected ? 'opacity-100' : 'opacity-30'}`}></div>
      </div>

      <div className="z-10 w-full max-w-6xl flex flex-col h-[90vh]">

        {/* Header */}
        <header className="flex justify-between items-center mb-8">
          <div className="flex items-center gap-3">
            <div className={`p-2 rounded-lg ${isConnected ? 'bg-indigo-500/20' : 'bg-zinc-800'}`}>
              <Activity className={`w-6 h-6 ${isConnected ? 'text-indigo-400' : 'text-zinc-500'}`} />
            </div>
            <div>
              <h1 className="text-2xl font-bold tracking-tight text-white">AURA <span className="text-zinc-500 font-normal">v2.5</span></h1>
              <p className="text-xs text-zinc-500">Universal Multilingual Voice Assistant</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
             <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-zinc-900 border border-zinc-800">
                <span className={`w-2 h-2 rounded-full ${isConnected ? 'bg-green-500 animate-pulse' : 'bg-red-500'}`}></span>
                <span className="text-xs font-mono text-zinc-400 uppercase">{connectionState}</span>
             </div>
             <button className="p-2 rounded-full hover:bg-zinc-800 text-zinc-400 transition-colors">
               <Settings size={20} />
             </button>
          </div>
        </header>

        {/* Info Panel */}
        <InfoPanel status={systemStatus} devMode={devMode} />

        {/* Main Content Area */}
        <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-6 min-h-0">

          {/* Left: Visualizer & Controls */}
          <div className="flex flex-col items-center justify-center bg-zinc-900/30 rounded-2xl border border-zinc-800/50 p-8 relative">
            <div className="absolute top-4 left-4 text-xs font-mono text-zinc-600">AUDIO VISUALIZER MODULE</div>

            <div className="flex-1 flex items-center justify-center w-full">
               <Visualizer volume={volume} active={isConnected} />
            </div>

            <div className="mt-8">
              <button 
                onClick={toggleConnection}
                className={`group relative flex items-center justify-center w-16 h-16 rounded-full transition-all duration-300 ${
                  isConnected 
                    ? 'bg-red-500/10 hover:bg-red-500/20 text-red-500 ring-2 ring-red-500/50' 
                    : isConnecting
                    ? 'bg-yellow-500/10 text-yellow-500 ring-2 ring-yellow-500/50 cursor-wait'
                    : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-lg shadow-indigo-500/30 ring-0'
                }`}
              >
                {isConnected ? <MicOff size={28} /> : <Mic size={28} className={isConnecting ? 'animate-pulse' : ''} />}

                {/* Ripple Effect for mic button */}
                {!isConnected && !isConnecting && (
                  <span className="absolute inset-0 rounded-full border border-indigo-400 opacity-0 group-hover:animate-ping"></span>
                )}
              </button>
              <p className="text-center mt-4 text-sm text-zinc-500">
                {isConnected ? 'Listening...' : isConnecting ? 'Connecting...' : 'Tap to Start'}
              </p>
            </div>
          </div>

          {/* Right: Chat/Log Interface */}
          <ChatInterface messages={transcripts} />

        </div>
      </div>
    </div>
  );
}

export default App;

import { useState, useRef, useEffect, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";
import { SYSTEM_INSTRUCTION, tools } from '../constants';
import { createPcmBlob, decodeAudioData, base64ToUint8Array } from '../utils/audio';
import { ConnectionState, Message } from '../types';

interface UseLiveSessionProps {
  onToolCall?: (name: string, args: any) => Promise<any>;
}

export const useLiveSession = ({ onToolCall }: UseLiveSessionProps) => {
  const [connectionState, setConnectionState] = useState<ConnectionState>(ConnectionState.DISCONNECTED);
  const [transcripts, setTranscripts] = useState<Message[]>([]);
  const [volume, setVolume] = useState<number>(0);

  // Refs for audio handling and session management
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const inputSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
