    if (sessionPromiseRef.current) {
       const session = await sessionPromiseRef.current;
       // There is no explicit close() method on the session object in the provided snippet?
       // The example says `session.close()` in "Live API Rules", but the snippet doesn't show it on the returned object from live.connect.
       // However, we can close the audio contexts and let the socket timeout/close from the server or client side logic.
