  useEffect(() => {
    let animationFrame: number;
    const updateOutputVolume = () => {
        if (analyserRef.current) {
            const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
            analyserRef.current.getByteFrequencyData(dataArray);
            let sum = 0;
            for(let i=0; i<dataArray.length; i++) {
                sum += dataArray[i];
            }
            const avg = sum / dataArray.length;
            // Normalize somewhat
            const norm = avg / 255; 
            // We want to combine input volume and output volume for a single "Activity" visualizer
            // But usually, only one happens at a time.
            if (norm > 0.01) {
                setVolume(prev => (prev * 0.5) + (norm * 0.5));
            }
        }
        animationFrame = requestAnimationFrame(updateOutputVolume);
    };
    updateOutputVolume();
    return () => cancelAnimationFrame(animationFrame);
  }, []);

  return {
    connect,
    disconnect,
    connectionState,
    transcripts,
    volume
  };
};

