import React, { useState, useCallback, useEffect } from 'react';
import { Mic, MicOff, Settings, Activity } from 'lucide-react';
import { useLiveSession } from './hooks/useLiveSession';
import Visualizer from './components/Visualizer';
import ChatInterface from './components/ChatInterface';
import InfoPanel from './components/InfoPanel';
import { ConnectionState, SystemStatus } from './types';

function App() {
  const [devMode, setDevMode] = useState(false);
  const [systemStatus, setSystemStatus] = useState<SystemStatus>({
    cpu: 12,
    ram: 6.4,
    battery: 85
  });

  // Simulate system activity
  useEffect(() => {
    const interval = setInterval(() => {
      setSystemStatus(prev => ({
        cpu: Math.min(100, Math.max(5, prev.cpu + (Math.random() * 10 - 5))),
        ram: prev.ram, // Static ram for stability
        battery: Math.max(0, prev.battery - 0.01)
      }));
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  const handleToolCall = useCallback(async (name: string, args: any) => {
    if (name === 'getSystemStatus') {
      return { 
        cpu: `${Math.round(systemStatus.cpu)}%`,
        ram: `${systemStatus.ram} GB`,
        battery: `${Math.round(systemStatus.battery)}%`,
        status: 'Operational'
      };
    }

    if (name === 'setReminder') {
      // In a real app, this would save to localStorage or backend
      return { 
        success: true, 
        message: `Reminder set for ${args.task} at ${args.time}` 
      };
    }

    if (name === 'toggleDeveloperMode') {
      const enabled = args.enabled;
      setDevMode(enabled);
      return {
        success: true,
        mode: enabled ? 'Developer Mode Enabled' : 'Standard Mode Enabled',
        info: enabled ? 'Verbose logging active. Technical details prioritized.' : 'Standard assistance active.'
      };
    }

    if (name === 'openWebsite') {
      const { url } = args;
      if (url) {
        // Attempt to open the window
        // Note: Browsers may block popups if not triggered by direct user interaction.
        // Since this is triggered by an async socket message, it might be blocked.
        // A visual cue to the user or a toast notification would be ideal in production.
        const win = window.open(url, '_blank', 'noopener,noreferrer');
        if (win) {
          return { success: true, message: `Successfully opened ${url}` };
        } else {
          return { success: false, message: `Failed to open ${url}. Popup might be blocked.` };
        }
      }
      return { success: false, message: 'No URL provided' };
    }

    return { error: 'Unknown tool' };
  }, [systemStatus]);

  const { connect, disconnect, connectionState, transcripts, volume } = useLiveSession({
    onToolCall: handleToolCall
  });

  const isConnected = connectionState === ConnectionState.CONNECTED;
  const isConnecting = connectionState === ConnectionState.CONNECTING;

  const toggleConnection = () => {
    if (isConnected || isConnecting) {
      disconnect();
    } else {
      connect();
    }
  };

