import { useState, useRef, useEffect, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";
import { SYSTEM_INSTRUCTION, tools } from '../constants';
import { createPcmBlob, decodeAudioData, base64ToUint8Array } from '../utils/audio';
import { ConnectionState, Message } from '../types';

interface UseLiveSessionProps {
  onToolCall?: (name: string, args: any) => Promise<any>;
}

export const useLiveSession = ({ onToolCall }: UseLiveSessionProps) => {
  const [connectionState, setConnectionState] = useState<ConnectionState>(ConnectionState.DISCONNECTED);
  const [transcripts, setTranscripts] = useState<Message[]>([]);
  const [volume, setVolume] = useState<number>(0);

  // Refs for audio handling and session management
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const inputSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const analyserRef = useRef<AnalyserNode | null>(null);

  // Helper to append transcripts
  const addTranscript = useCallback((role: 'user' | 'assistant' | 'system', text: string) => {
    setTranscripts(prev => [
      ...prev,
      { id: Date.now().toString() + Math.random(), role, text, timestamp: new Date() }
    ]);
  }, []);

  const connect = useCallback(async () => {
    if (!process.env.API_KEY) {
      addTranscript('system', 'Error: API Key is missing.');
      setConnectionState(ConnectionState.ERROR);
      return;
    }

    // Ensure any existing session is cleaned up before connecting
    if (connectionState === ConnectionState.CONNECTED || connectionState === ConnectionState.CONNECTING) {
        return;
    }

    try {
      setConnectionState(ConnectionState.CONNECTING);

      // Initialize Audio Contexts
      // Removing fixed sampleRate to prevent "Network Error" / NotSupportedError on some devices
      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      inputContextRef.current = inputCtx;
      outputContextRef.current = outputCtx;

      // Audio Analyser for visualization
      const analyser = outputCtx.createAnalyser();
      analyser.fftSize = 256;
      analyserRef.current = analyser;

      // Setup Input Stream
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const source = inputCtx.createMediaStreamSource(stream);
      inputSourceRef.current = source;

      // Setup Processor (Deprecated but functional for standard raw PCM processing in browser)
      const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
      processorRef.current = scriptProcessor;

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: SYSTEM_INSTRUCTION,
          tools: [{ functionDeclarations: tools }],
          inputAudioTranscription: {}, 
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log('Session connected');
            setConnectionState(ConnectionState.CONNECTED);
            addTranscript('system', 'Voice Assistant Connected. Start speaking...');

            // Connect Audio Nodes
            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              // Calculate volume for visualization (input side)
              let sum = 0;
              for (let i = 0; i < inputData.length; i++) {
                 sum += inputData[i] * inputData[i];
              }
              const rms = Math.sqrt(sum / inputData.length);
              setVolume(v => (v * 0.8) + (rms * 2)); // Smooth update

              // Use the actual sample rate from the context, as browsers might ignore the requested 16000
              // The API handles various rates if specified in the MIME type
              const pcmBlob = createPcmBlob(inputData, inputCtx.sampleRate);
              if (sessionPromiseRef.current) {
                sessionPromiseRef.current.then(session => {
                    session.sendRealtimeInput({ media: pcmBlob });
                });
              }
            };
          },
          onmessage: async (message: LiveServerMessage) => {
            // Handle Audio Output
            const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData) {
              const ctx = outputContextRef.current;
              if (ctx && ctx.state !== 'closed') {
                 // Sync timing
                 nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                 // We decode 24kHz audio (standard from Gemini)
                 const audioBuffer = await decodeAudioData(
                   base64ToUint8Array(audioData),
                   ctx,
                   24000, 
                   1
                 );

                 const source = ctx.createBufferSource();
                 source.buffer = audioBuffer;

                 // Connect to analyser for output visualization
                 if (analyserRef.current) {
                    source.connect(analyserRef.current);
                    analyserRef.current.connect(ctx.destination);
                 } else {
                    source.connect(ctx.destination);
                 }

                 source.addEventListener('ended', () => {
                    audioSourcesRef.current.delete(source);
                 });

                 source.start(nextStartTimeRef.current);
                 audioSourcesRef.current.add(source);
                 nextStartTimeRef.current += audioBuffer.duration;
              }
            }

            // Handle Transcripts
            // We use turnComplete to avoid flooding the chat with partial streaming updates
            if (message.serverContent?.turnComplete) {
               // You could handle turn completion logic here if needed
            }

            // Check Output Transcription (Model)
            const outputTranscript = (message.serverContent as any)?.outputTranscription?.text;
             if (outputTranscript && message.serverContent?.turnComplete) {
                 addTranscript('assistant', outputTranscript);
             }

            // Handle Tool Calls
            if (message.toolCall) {
                addTranscript('system', 'Executing assistant tools...');
                for (const fc of message.toolCall.functionCalls) {
                    console.log('Tool Call:', fc.name, fc.args);
                    let result: any = { result: 'Success' };

                    if (onToolCall) {
                       try {
                           const output = await onToolCall(fc.name, fc.args);
                           result = output;
                           addTranscript('system', `Tool executed: ${fc.name}`);
                       } catch (e) {
                           console.error('Tool execution failed', e);
                           result = { error: 'Failed to execute tool' };
                       }
                    }

                    if (sessionPromiseRef.current) {
                        sessionPromiseRef.current.then(session => {
                            session.sendToolResponse({
                                functionResponses: {
                                    id: fc.id,
                                    name: fc.name,
                                    response: result
                                }
                            });
                        });
                    }
                }
            }
          },
          onclose: () => {
            console.log('Session closed');
            setConnectionState(ConnectionState.DISCONNECTED);
            addTranscript('system', 'Session ended.');
          },
          onerror: (err) => {
            console.error('Session error:', err);
            setConnectionState(ConnectionState.ERROR);
            addTranscript('system', 'Connection error occurred.');
          }
        }
      });

      sessionPromiseRef.current = sessionPromise;

    } catch (error) {
      console.error('Connection failed:', error);
      setConnectionState(ConnectionState.ERROR);
    }
  }, [addTranscript, onToolCall, connectionState]);

  const disconnect = useCallback(async () => {
    if (sessionPromiseRef.current) {
       const session = await sessionPromiseRef.current;
       try {
         (session as any).close();
       } catch (e) { console.warn('Could not close session explicitly', e)}
    }

    // Cleanup Audio
    if (inputContextRef.current) {
        if (inputContextRef.current.state !== 'closed') {
             try {
                await inputContextRef.current.close();
             } catch(e) {
                console.warn("Error closing input context", e);
             }
        }
        inputContextRef.current = null;
    }

    if (outputContextRef.current) {
        if (outputContextRef.current.state !== 'closed') {
            try {
                await outputContextRef.current.close();
            } catch(e) {
                console.warn("Error closing output context", e);
            }
        }
        outputContextRef.current = null;
    }

    if (processorRef.current) {
        processorRef.current.disconnect();
        processorRef.current = null;
    }
    if (inputSourceRef.current) {
        inputSourceRef.current.disconnect();
        inputSourceRef.current = null;
    }

    // Stop all playing sources
    audioSourcesRef.current.forEach(source => {
        try { source.stop(); } catch (e) {}
    });
    audioSourcesRef.current.clear();

    setConnectionState(ConnectionState.DISCONNECTED);
    setVolume(0);
    sessionPromiseRef.current = null;
  }, []);

  // Update volume from analyser for output audio visualization
  useEffect(() => {
    let animationFrame: number;
    const updateOutputVolume = () => {
        if (analyserRef.current) {
            const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
            analyserRef.current.getByteFrequencyData(dataArray);
            let sum = 0;
            for(let i=0; i<dataArray.length; i++) {
                sum += dataArray[i];
            }
            const avg = sum / dataArray.length;
            // Normalize somewhat
            const norm = avg / 255; 
            if (norm > 0.01) {
                setVolume(prev => (prev * 0.5) + (norm * 0.5));
            }
        }
        animationFrame = requestAnimationFrame(updateOutputVolume);
    };
    updateOutputVolume();
    return () => cancelAnimationFrame(animationFrame);
  }, []);

  return {
    connect,
    disconnect,
    connectionState,
    transcripts,
    volume
  };
};

import { Blob } from "@google/genai";

export function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function arrayBufferToBase64(buffer: ArrayBuffer): string {
  let binary = '';
  const bytes = new Uint8Array(buffer);
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

// Simple linear interpolation to downsample audio to target rate (16kHz)
export function downsampleBuffer(buffer: Float32Array, inputRate: number, outputRate: number = 16000): Float32Array {
  if (outputRate === inputRate) {
    return buffer;
  }
  const sampleRateRatio = inputRate / outputRate;
  const newLength = Math.round(buffer.length / sampleRateRatio);
  const result = new Float32Array(newLength);
  let offsetResult = 0;
  let offsetBuffer = 0;

  while (offsetResult < newLength) {
    const nextOffsetBuffer = Math.round((offsetResult + 1) * sampleRateRatio);
    // Use average value of accumulated samples for simple anti-aliasing
    let accum = 0, count = 0;
    for (let i = offsetBuffer; i < nextOffsetBuffer && i < buffer.length; i++) {
      accum += buffer[i];
      count++;
    }
    result[offsetResult] = count > 0 ? accum / count : 0;
    offsetResult++;
    offsetBuffer = nextOffsetBuffer;
  }
  return result;
}

export function createPcmBlob(data: Float32Array, sampleRate: number): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    // Clamp values to [-1, 1] range to prevent clipping/distortion
    const s = Math.max(-1, Math.min(1, data[i]));
    // Convert float32 to int16 PCM
    int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
  }
  return {
    data: arrayBufferToBase64(int16.buffer),
    mimeType: `audio/pcm;rate=${sampleRate}`,
  };
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

