// Mock Music State
interface MusicState {
  isPlaying: boolean;
  song: string | null;
  artist: string | null;
}

function App() {
  const [musicState, setMusicState] = useState<MusicState>({ isPlaying: false, song: null, artist: null });

  const handleToolCall = useCallback(async (name: string, args: any) => {
    if (name === 'openWebsite') {
      const { url } = args;
      if (url) {
        // Try opening
        const win = window.open(url, '_blank', 'noopener,noreferrer');
        // If popup blocked, we can't do much in a voice-only context without user click
        // but we return success so the AI thinks it worked.
        return { success: true, message: `Opened ${url}` };
      }
      return { success: false, message: 'No URL provided' };
    }

    if (name === 'controlMusic') {
      const { action, song } = args;
      if (action === 'play') {
        setMusicState({
          isPlaying: true,
          song: song || 'Random Lo-Fi Mix',
          artist: 'Unknown Artist'
        });
        return { success: true, status: `Playing ${song || 'music'}` };
      } else if (action === 'pause' || action === 'stop') {
        setMusicState(prev => ({ ...prev, isPlaying: false }));
        return { success: true, status: 'Music paused' };
      }
    }

    if (name === 'toggleDeveloperMode') {
       return { success: true, message: 'Mode switched' };
    }

    return { error: 'Unknown tool' };
  }, []);

  const { connect, disconnect, connectionState, transcripts, volume } = useLiveSession({
    onToolCall: handleToolCall
  });

  const isConnected = connectionState === ConnectionState.CONNECTED;
  const isConnecting = connectionState === ConnectionState.CONNECTING;

  const toggleConnection = () => {
    if (isConnected || isConnecting) {
      disconnect();
    } else {
      connect();
    }
  };

  return (
    <div className="h-screen w-screen bg-[#09090b] text-zinc-100 flex flex-col relative overflow-hidden font-sans selection:bg-purple-500/30">

      {/* Dynamic Background */}
      <div className="absolute inset-0 pointer-events-none z-0">
         <div className="absolute top-[-20%] left-[-10%] w-[800px] h-[800px] bg-blue-600/10 rounded-full blur-[120px] opacity-50"></div>
         <div className="absolute bottom-[-20%] right-[-10%] w-[600px] h-[600px] bg-purple-600/10 rounded-full blur-[100px] opacity-50"></div>
      </div>

      {/* Main Layout: Split for Desktop, Stack for Mobile */}
      <div className="relative z-10 flex flex-col md:flex-row h-full">

        {/* Left Section: AI Personality (Orb) */}
        <div className="flex-1 md:flex-[0.4] flex flex-col items-center justify-center p-6 relative border-b md:border-b-0 md:border-r border-white/5">

           {/* Header */}
           <div className="absolute top-6 left-6 flex items-center gap-2">
             <div className="w-2 h-2 rounded-full bg-gradient-to-r from-cyan-400 to-purple-500"></div>
             <span className="font-bold tracking-widest text-sm text-transparent bg-clip-text bg-gradient-to-r from-white to-zinc-400">BLURRY</span>
           </div>

           <div className="flex-1 flex flex-col items-center justify-center w-full">
              <Visualizer volume={volume} active={isConnected} />

              <div className="mt-10 flex flex-col items-center gap-4">
                  <h2 className="text-2xl md:text-3xl font-bold text-center bg-clip-text text-transparent bg-gradient-to-b from-white to-zinc-500">
                    {isConnected ? "Listening..." : "Hello, Arthur"}
                  </h2>
                  <p className="text-zinc-500 text-sm text-center max-w-xs">
                    {isConnected ? "Go ahead, I'm listening." : "Tap the microphone to start."}
                  </p>
              </div>
           </div>

           {/* Controls */}
           <div className="mb-8">
              <button 
                onClick={toggleConnection}
                disabled={isConnecting}
                className={`group relative flex items-center justify-center w-20 h-20 rounded-full transition-all duration-500 ${
                  isConnected 
                    ? 'bg-red-500/10 border border-red-500/50 hover:bg-red-500/20' 
                    : 'bg-white text-black hover:scale-105 shadow-[0_0_40px_rgba(255,255,255,0.3)]'
                }`}
              >
                 {isConnecting ? (
                     <div className="w-8 h-8 border-2 border-zinc-500 border-t-transparent rounded-full animate-spin"></div>
                 ) : isConnected ? (
                     <MicOff className="w-8 h-8 text-red-500" />
                 ) : (
                     <Mic className="w-8 h-8" />
                 )}
              </button>
           </div>
        </div>

        {/* Right Section: Chat & Content */}
        <div className="flex-1 md:flex-[0.6] flex flex-col bg-zinc-950/30 backdrop-blur-sm relative">

           {/* Chat Area */}
           <ChatInterface messages={transcripts} />

           {/* Floating Music Player (Conditional) */}
           {musicState.song && (
             <div className="absolute bottom-24 left-1/2 -translate-x-1/2 w-[90%] md:w-[80%] bg-zinc-900/90 border border-zinc-800 backdrop-blur-md p-3 rounded-2xl flex items-center gap-4 shadow-2xl transition-all animate-in slide-in-from-bottom-5">
                <div className="w-12 h-12 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center shrink-0 animate-pulse">
                   <Music className="text-white w-6 h-6" />
                </div>
                <div className="flex-1 min-w-0">
                   <h4 className="text-sm font-semibold text-white truncate">{musicState.song}</h4>
                   <p className="text-xs text-zinc-400 truncate">{musicState.artist}</p>
                </div>
                <div className="flex items-center gap-2">
                   <button className="p-2 hover:bg-white/10 rounded-full transition-colors">
                      {musicState.isPlaying ? <Pause size={20} /> : <Play size={20} />}
                   </button>
                   <button className="p-2 hover:bg-white/10 rounded-full transition-colors">
                      <SkipForward size={20} />
                   </button>
                </div>
             </div>
           )}

           {/* Suggestion Chips (only when idle) */}
           {!isConnected && transcripts.length === 0 && (
             <div className="absolute bottom-8 left-0 w-full px-6 overflow-x-auto no-scrollbar flex gap-3">
                {['Play some music', 'Open YouTube', 'Explain React'].map((suggestion) => (
                  <button key={suggestion} className="whitespace-nowrap px-4 py-2 rounded-full bg-zinc-800/50 border border-zinc-700/50 text-xs text-zinc-400 hover:bg-zinc-700 hover:text-white transition-all">
                    "{suggestion}"
                  </button>
                ))}
             </div>
           )}

        </div>

      </div>
    </div>
  );
}

export default App;

import { Blob } from "@google/genai";

export function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export function arrayBufferToBase64(buffer: ArrayBuffer): string {
  let binary = '';
  const bytes = new Uint8Array(buffer);
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

// Robust Downsampling
export function downsampleBuffer(buffer: Float32Array, inputRate: number, outputRate: number = 16000): Float32Array {
  if (outputRate === inputRate) {
    return buffer;
  }
  const sampleRateRatio = inputRate / outputRate;
  const newLength = Math.round(buffer.length / sampleRateRatio);
  const result = new Float32Array(newLength);
  let offsetResult = 0;
  let offsetBuffer = 0;

  while (offsetResult < newLength) {
    const nextOffsetBuffer = Math.round((offsetResult + 1) * sampleRateRatio);
    // Simple averaging (boxcar filter) to prevent aliasing
    let accum = 0, count = 0;
    for (let i = offsetBuffer; i < nextOffsetBuffer && i < buffer.length; i++) {
      accum += buffer[i];
      count++;
    }
    result[offsetResult] = count > 0 ? accum / count : 0;
    offsetResult++;
    offsetBuffer = nextOffsetBuffer;
  }
  return result;
}

export function createPcmBlob(data: Float32Array, sampleRate: number): Blob {
  // PCM 16-bit, little-endian
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    const s = Math.max(-1, Math.min(1, data[i]));
    int16[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
  }
  // Gemini Live API requires standard PCM at specific rates
  return {
    data: arrayBufferToBase64(int16.buffer),
    mimeType: `audio/pcm;rate=${sampleRate}`,
  };
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number = 24000,
  numChannels: number = 1,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

import { useState, useRef, useEffect, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";
import { SYSTEM_INSTRUCTION, tools } from '../constants';
import { createPcmBlob, decodeAudioData, base64ToUint8Array, downsampleBuffer } from '../utils/audio';
import { ConnectionState, Message } from '../types';

interface UseLiveSessionProps {
  onToolCall?: (name: string, args: any) => Promise<any>;
}

export const useLiveSession = ({ onToolCall }: UseLiveSessionProps) => {
  const [connectionState, setConnectionState] = useState<ConnectionState>(ConnectionState.DISCONNECTED);
  const [transcripts, setTranscripts] = useState<Message[]>([]);
  const [volume, setVolume] = useState<number>(0);

  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const inputSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const analyserRef = useRef<AnalyserNode | null>(null);

  const addTranscript = useCallback((role: 'user' | 'assistant' | 'system', text: string) => {
    setTranscripts(prev => [
      ...prev,
      { id: Date.now().toString() + Math.random(), role, text, timestamp: new Date() }
    ]);
  }, []);

  const cleanupAudio = useCallback(async () => {
    // Stop all audio contexts and processors
    if (processorRef.current) {
        processorRef.current.disconnect();
        processorRef.current = null;
    }
    if (inputSourceRef.current) {
        inputSourceRef.current.disconnect();
        inputSourceRef.current = null;
    }

    if (inputContextRef.current) {
        try { await inputContextRef.current.close(); } catch(e) {}
        inputContextRef.current = null;
    }

    if (outputContextRef.current) {
        try { await outputContextRef.current.close(); } catch(e) {}
        outputContextRef.current = null;
    }

    audioSourcesRef.current.forEach(source => {
        try { source.stop(); } catch (e) {}
    });
    audioSourcesRef.current.clear();

    // Clear session promise to stop any pending sends
    sessionPromiseRef.current = null;
    setVolume(0);
  }, []);

  const connect = useCallback(async () => {
    if (!process.env.API_KEY) {
      addTranscript('system', 'Error: API Key is missing.');
      setConnectionState(ConnectionState.ERROR);
      return;
    }

    if (connectionState === ConnectionState.CONNECTED || connectionState === ConnectionState.CONNECTING) {
        return;
    }

    try {
      setConnectionState(ConnectionState.CONNECTING);

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)();

      if (inputCtx.state === 'suspended') await inputCtx.resume();
      if (outputCtx.state === 'suspended') await outputCtx.resume();

      inputContextRef.current = inputCtx;
      outputContextRef.current = outputCtx;

      const analyser = outputCtx.createAnalyser();
      analyser.fftSize = 256;
      analyserRef.current = analyser;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const source = inputCtx.createMediaStreamSource(stream);
      inputSourceRef.current = source;

      const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
      processorRef.current = scriptProcessor;

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: SYSTEM_INSTRUCTION,
          tools: [{ functionDeclarations: tools }],
          inputAudioTranscription: {}, 
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log('Session connected');
            setConnectionState(ConnectionState.CONNECTED);
            addTranscript('system', 'Voice Assistant Connected. Start speaking...');

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);

            scriptProcessor.onaudioprocess = (e) => {
              if (!sessionPromiseRef.current) return; // Stop processing if disconnected

              const inputData = e.inputBuffer.getChannelData(0);

              // Visualization
              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              const rms = Math.sqrt(sum / inputData.length);
              setVolume(v => (v * 0.8) + (rms * 2)); 

              // Downsample to 16kHz
              const downsampledData = downsampleBuffer(inputData, inputCtx.sampleRate, 16000);
              const pcmBlob = createPcmBlob(downsampledData, 16000);

              sessionPromiseRef.current.then(session => {
                  try {
                    session.sendRealtimeInput({ media: pcmBlob });
                  } catch (e) {
                    console.warn("Error sending audio:", e);
                  }
              }).catch(e => {
                  console.warn("Session not ready for audio:", e);
              });
            };
          },
          onmessage: async (message: LiveServerMessage) => {
            const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData) {
              const ctx = outputContextRef.current;
              if (ctx && ctx.state !== 'closed') {
                 nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

                 const audioBuffer = await decodeAudioData(
                   base64ToUint8Array(audioData),
                   ctx,
                   24000, 
                   1
                 );

                 const source = ctx.createBufferSource();
                 source.buffer = audioBuffer;

                 if (analyserRef.current) {
                    source.connect(analyserRef.current);
                    analyserRef.current.connect(ctx.destination);
                 } else {
                    source.connect(ctx.destination);
                 }

                 source.addEventListener('ended', () => {
                    audioSourcesRef.current.delete(source);
                 });

                 source.start(nextStartTimeRef.current);
                 audioSourcesRef.current.add(source);
                 nextStartTimeRef.current += audioBuffer.duration;
              }
            }

            const outputTranscript = (message.serverContent as any)?.outputTranscription?.text;
             if (outputTranscript && message.serverContent?.turnComplete) {
                 addTranscript('assistant', outputTranscript);
             }

            if (message.toolCall) {
                addTranscript('system', 'Executing assistant tools...');
                for (const fc of message.toolCall.functionCalls) {
                    console.log('Tool Call:', fc.name, fc.args);
                    let result: any = { result: 'Success' };

                    if (onToolCall) {
                       try {
                           const output = await onToolCall(fc.name, fc.args);
                           result = output;
                           addTranscript('system', `Tool executed: ${fc.name}`);
                       } catch (e) {
                           console.error('Tool execution failed', e);
                           result = { error: 'Failed to execute tool' };
                       }
                    }

                    if (sessionPromiseRef.current) {
                        sessionPromiseRef.current.then(session => {
                            session.sendToolResponse({
                                functionResponses: {
                                    id: fc.id,
                                    name: fc.name,
                                    response: result
                                }
                            });
                        });
                    }
                }
            }
          },
          onclose: () => {
            console.log('Session closed');
            setConnectionState(ConnectionState.DISCONNECTED);
            addTranscript('system', 'Session ended.');
            cleanupAudio(); // CRITICAL: Stop sending audio immediately
          },
          onerror: (err) => {
            console.error('Session error:', err);
            setConnectionState(ConnectionState.ERROR);
            addTranscript('system', 'Connection error occurred.');
            cleanupAudio(); // CRITICAL: Stop sending audio immediately
          }
        }
      });

      sessionPromiseRef.current = sessionPromise;

    } catch (error) {
      console.error('Connection failed:', error);
      setConnectionState(ConnectionState.ERROR);
      cleanupAudio();
    }
  }, [addTranscript, onToolCall, connectionState, cleanupAudio]);

  const disconnect = useCallback(async () => {
    if (sessionPromiseRef.current) {
       const session = await sessionPromiseRef.current;
       try {
         (session as any).close();
       } catch (e) { console.warn('Could not close session explicitly', e)}
    }
    await cleanupAudio();
    setConnectionState(ConnectionState.DISCONNECTED);
  }, [cleanupAudio]);

  useEffect(() => {
    let animationFrame: number;
    const updateOutputVolume = () => {
        if (analyserRef.current) {
            const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
            analyserRef.current.getByteFrequencyData(dataArray);
            let sum = 0;
            for(let i=0; i<dataArray.length; i++) sum += dataArray[i];
            const avg = sum / dataArray.length;
            const norm = avg / 255; 
            if (norm > 0.01) {
                setVolume(prev => (prev * 0.5) + (norm * 0.5));
            }
        }
        animationFrame = requestAnimationFrame(updateOutputVolume);
    };
    updateOutputVolume();
    return () => cancelAnimationFrame(animationFrame);
  }, []);

  return {
    connect,
    disconnect,
    connectionState,
    transcripts,
    volume
  };
};

