import { ConnectionState } from './types';

// Enhanced Music State
interface MusicState {
  isPlaying: boolean;
  song: string | null;
  artist: string | null;
  url: string | null;
  error?: string | null;
}

// 🎵 SMART TRACK LIBRARY
// Reliable, copyright-free streams mapped to vibes/languages
const TRACK_LIBRARY: Record<string, { url: string; artist: string; label: string }> = {
  // Hindi / Bollywood Vibe
  'hindi': { url: 'https://cdn.pixabay.com/audio/2023/09/20/audio_034927f805.mp3', artist: 'Bollywood LoFi', label: 'Desi Vibes' },
  'punjabi': { url: 'https://cdn.pixabay.com/audio/2023/05/23/audio_82c219d95f.mp3', artist: 'Punjabi Beats', label: 'Bhangra Flow' },

  // English / Pop
  'pop': { url: 'https://cdn.pixabay.com/audio/2022/01/18/audio_d2166e5b84.mp3', artist: 'Top 40 Hit', label: 'Pop Radio' },
  'rock': { url: 'https://cdn.pixabay.com/audio/2022/03/24/audio_3497d36a3f.mp3', artist: 'Indie Rocker', label: 'Rock Station' },

  // Moods
  'lofi': { url: 'https://cdn.pixabay.com/audio/2022/05/27/audio_1808fbf07a.mp3', artist: 'Chill Beats', label: 'Study Mode' },
  'jazz': { url: 'https://cdn.pixabay.com/audio/2022/02/10/audio_fc8c857707.mp3', artist: 'Smooth Jazz', label: 'Cafe Vibes' },
  'party': { url: 'https://cdn.pixabay.com/audio/2024/01/16/audio_e2b992254f.mp3', artist: 'Club Mix', label: 'Party Central' },

  // Default Fallback
  'default': { url: 'https://cdn.pixabay.com/audio/2022/11/22/audio_febc508520.mp3', artist: 'Unknown Artist', label: 'Streaming...' }
};

function App() {
  const [musicState, setMusicState] = useState<MusicState>({ 
    isPlaying: false, 
    song: null, 
    artist: null,
    url: null,
    error: null
  });

  const audioRef = useRef<HTMLAudioElement | null>(null);

  // 🔄 Sync Audio Element with State
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const playAudio = async () => {
      try {
        if (musicState.isPlaying && musicState.url) {
          // Only change source if it's different to prevent reloading
          if (audio.src !== musicState.url) {
             audio.src = musicState.url;
             await audio.load();
          }
          await audio.play();
          setMusicState(prev => ({ ...prev, error: null }));
        } else {
          audio.pause();
        }
      } catch (err) {
        console.error("Playback failed:", err);
        setMusicState(prev => ({ 
          ...prev, 
          isPlaying: false, 
          error: "Playback blocked. Click play manually." 
        }));
      }
    };

    playAudio();
  }, [musicState.isPlaying, musicState.url]);

  const handleToolCall = useCallback(async (name: string, args: any) => {
    console.log('App Handling Tool:', name, args);

    if (name === 'openWebsite') {
      const { url } = args;
      if (url) {
        window.open(url, '_blank', 'noopener,noreferrer');
        return { success: true, message: `Opened ${url}` };
      }
      return { success: false, message: 'No URL provided' };
    }

    if (name === 'controlMusic') {
      const { action, song } = args;

      if (action === 'play') {
        const songQuery = (song || '').toLowerCase();

        // 🧠 Smart Genre Matching
        let selectedTrack = TRACK_LIBRARY['default'];

        if (songQuery.includes('hindi') || songQuery.includes('bollywood') || songQuery.includes('arijit') || songQuery.includes('t-series')) {
          selectedTrack = TRACK_LIBRARY['hindi'];
        } else if (songQuery.includes('punjabi') || songQuery.includes('sidhu') || songQuery.includes('ap dhillon')) {
          selectedTrack = TRACK_LIBRARY['punjabi'];
        } else if (songQuery.includes('rock') || songQuery.includes('metal')) {
          selectedTrack = TRACK_LIBRARY['rock'];
        } else if (songQuery.includes('pop') || songQuery.includes('swift') || songQuery.includes('english')) {
          selectedTrack = TRACK_LIBRARY['pop'];
        } else if (songQuery.includes('jazz') || songQuery.includes('blues')) {
          selectedTrack = TRACK_LIBRARY['jazz'];
        } else if (songQuery.includes('chill') || songQuery.includes('lofi') || songQuery.includes('study')) {
          selectedTrack = TRACK_LIBRARY['lofi'];
        }

        // If specific song requested, use that name for UI, but play the matched genre track
        const displaySong = song || selectedTrack.label;
        const displayArtist = song ? 'AI Requested Selection' : selectedTrack.artist;

        setMusicState({
          isPlaying: true,
          song: displaySong,
          artist: displayArtist,
          url: selectedTrack.url,
          error: null
        });

        return { success: true, status: `Playing ${displaySong}` };

      } else if (action === 'pause' || action === 'stop') {
        setMusicState(prev => ({ ...prev, isPlaying: false }));
        return { success: true, status: 'Music paused' };
      }
    }

    if (name === 'toggleDeveloperMode') {
       return { success: true, message: 'Mode switched' };
    }

    return { error: 'Unknown tool' };
  }, []);

  const { connect, disconnect, connectionState, transcripts, volume } = useLiveSession({
    onToolCall: handleToolCall
  });

  const isConnected = connectionState === ConnectionState.CONNECTED;
  const isConnecting = connectionState === ConnectionState.CONNECTING;

  const toggleConnection = () => {
    if (isConnected || isConnecting) {
      disconnect();
    } else {
      connect();
    }
  };

  return (
    <div className="h-screen w-screen bg-[#09090b] text-zinc-100 flex flex-col relative overflow-hidden font-sans selection:bg-purple-500/30">

      {/* Hidden Audio Element */}
      <audio 
        ref={audioRef} 
        onEnded={() => setMusicState(prev => ({...prev, isPlaying: false}))}
        onError={(e) => {
            console.error("Audio Error", e);
            setMusicState(prev => ({...prev, isPlaying: false, error: "Stream unavailable"}));
        }} 
      />

      {/* Dynamic Background */}
      <div className="absolute inset-0 pointer-events-none z-0">
         <div className="absolute top-[-20%] left-[-10%] w-[800px] h-[800px] bg-blue-600/10 rounded-full blur-[120px] opacity-50 animate-pulse"></div>
         <div className="absolute bottom-[-20%] right-[-10%] w-[600px] h-[600px] bg-purple-600/10 rounded-full blur-[100px] opacity-50"></div>
      </div>

      {/* Main Layout */}
      <div className="relative z-10 flex flex-col md:flex-row h-full">

        {/* Left Section: AI Personality (Orb) */}
        <div className="flex-1 md:flex-[0.4] flex flex-col items-center justify-center p-6 relative border-b md:border-b-0 md:border-r border-white/5 bg-zinc-950/20 backdrop-blur-sm">

           {/* Header */}
           <div className="absolute top-6 left-6 flex items-center gap-2">
             <div className="w-2 h-2 rounded-full bg-gradient-to-r from-cyan-400 to-purple-500 shadow-[0_0_10px_rgba(168,85,247,0.5)]"></div>
             <span className="font-bold tracking-widest text-sm text-transparent bg-clip-text bg-gradient-to-r from-white to-zinc-400">BLURRY</span>
           </div>

           <div className="flex-1 flex flex-col items-center justify-center w-full transform transition-all duration-700 hover:scale-105">
              <Visualizer volume={volume} active={isConnected} />

              <div className="mt-12 flex flex-col items-center gap-2">
                  <h2 className="text-2xl font-bold text-center bg-clip-text text-transparent bg-gradient-to-b from-white to-zinc-500 transition-all duration-500">
                    {isConnected ? (volume > 0.05 ? "Listening..." : "Blurry Online") : "Hello, User"}
                  </h2>
              </div>
           </div>

           {/* Mic Control */}
           <div className="mb-10">
              <button 
                onClick={toggleConnection}
                disabled={isConnecting}
                className={`group relative flex items-center justify-center w-20 h-20 rounded-full transition-all duration-500 ${
                  isConnected 
                    ? 'bg-red-500/10 border border-red-500/50 hover:bg-red-500/20 shadow-[0_0_30px_rgba(239,68,68,0.2)]' 
                    : 'bg-white text-black hover:scale-110 shadow-[0_0_40px_rgba(255,255,255,0.4)]'
                }`}
              >
                 {isConnecting ? (
                     <div className="w-8 h-8 border-2 border-zinc-500 border-t-transparent rounded-full animate-spin"></div>
                 ) : isConnected ? (
                     <MicOff className="w-8 h-8 text-red-500 transition-transform group-hover:scale-110" />
                 ) : (
                     <Mic className="w-8 h-8 transition-transform group-hover:scale-110" />
                 )}
              </button>
           </div>
        </div>

        {/* Right Section: Chat & Content */}
        <div className="flex-1 md:flex-[0.6] flex flex-col bg-zinc-950/40 backdrop-blur-md relative shadow-2xl">

           {/* Chat Area */}
           <ChatInterface messages={transcripts} />

           {/* Music Player Error Toast */}
           {musicState.error && (
               <div className="absolute top-4 left-1/2 -translate-x-1/2 bg-red-500/90 text-white px-4 py-2 rounded-full text-xs font-bold shadow-lg flex items-center gap-2 animate-in slide-in-from-top-2 z-50">
                   <AlertCircle size={14} />
                   {musicState.error}
               </div>
           )}

           {/* Floating Music Player Widget (High Z-Index) */}
           {musicState.isPlaying && (
             <div className="absolute bottom-8 left-1/2 -translate-x-1/2 w-[90%] md:w-[80%] bg-zinc-900/95 border border-zinc-700/50 backdrop-blur-xl p-4 rounded-3xl flex items-center gap-5 shadow-2xl z-50 animate-in slide-in-from-bottom-10 ring-1 ring-white/10">

                {/* Album Art */}
                <div className="w-14 h-14 bg-gradient-to-br from-indigo-500 via-purple-500 to-pink-500 rounded-2xl flex items-center justify-center shrink-0 animate-pulse shadow-lg">
                   <Music className="text-white w-7 h-7 drop-shadow-md" />
                </div>

                <div className="flex-1 min-w-0">
                   <h4 className="text-base font-bold text-white truncate capitalize">{musicState.song}</h4>
                   <p className="text-xs text-zinc-400 truncate font-medium">{musicState.artist}</p>

                   {/* Fake Progress Bar */}
                   <div className="w-full h-1 bg-zinc-800 rounded-full mt-2 overflow-hidden">
                      <div className="h-full bg-white/80 w-1/3 rounded-full animate-pulse"></div>
                   </div>
                </div>

                <div className="flex items-center gap-1">
                   <button 
                     onClick={() => setMusicState(p => ({...p, isPlaying: !p.isPlaying}))}
                     className="p-3 hover:bg-white/10 rounded-full transition-colors active:scale-95"
                   >
                      {musicState.isPlaying ? <Pause size={24} fill="currentColor" /> : <Play size={24} fill="currentColor" />}
                   </button>
                   <button 
                     onClick={() => setMusicState(p => ({...p, isPlaying: false}))}
                     className="p-3 hover:bg-white/10 rounded-full transition-colors active:scale-95">
                      <SkipForward size={24} fill="currentColor" />
                   </button>
                </div>
             </div>
           )}

           {/* Quick Actions (only when idle and music not playing) */}
           {!isConnected && transcripts.length === 0 && !musicState.isPlaying && (
             <div className="absolute bottom-8 left-0 w-full px-8 overflow-x-auto no-scrollbar flex gap-3 justify-center">
                {['Play Hindi Music', 'Play Pop', 'Search React'].map((suggestion) => (
                  <button key={suggestion} className="whitespace-nowrap px-5 py-2.5 rounded-full bg-zinc-800/80 border border-zinc-700/50 text-xs font-medium text-zinc-300 hover:bg-white hover:text-black hover:scale-105 transition-all shadow-lg">
                    {suggestion}
                  </button>
                ))}
             </div>
           )}

        </div>

      </div>
    </div>
  );
}

export default App;

