        }
        return { success: false, message: 'No query provided' };
    }

    if (name === 'controlMusic') {
      const { action, song } = args;

      if (action === 'play') {
        const songQuery = (song || '').toLowerCase();

        // Match Genre
        let selectedTrack = TRACK_LIBRARY['default'];
        if (songQuery.includes('hindi') || songQuery.includes('bollywood')) selectedTrack = TRACK_LIBRARY['hindi'];
        else if (songQuery.includes('punjabi')) selectedTrack = TRACK_LIBRARY['punjabi'];
        else if (songQuery.includes('rock')) selectedTrack = TRACK_LIBRARY['rock'];
        else if (songQuery.includes('pop')) selectedTrack = TRACK_LIBRARY['pop'];
        else if (songQuery.includes('jazz')) selectedTrack = TRACK_LIBRARY['jazz'];
        else if (songQuery.includes('lofi') || songQuery.includes('relax')) selectedTrack = TRACK_LIBRARY['lofi'];

        setMusicState({
          isPlaying: true,
          song: song || selectedTrack.label,
          artist: selectedTrack.artist,
          url: selectedTrack.url,
          error: null
        });

        return { success: true, status: `Playing ${song || selectedTrack.label}` };

      } else if (action === 'pause' || action === 'stop') {
        setMusicState(prev => ({ ...prev, isPlaying: false }));
        return { success: true, status: 'Music paused' };
      }
    }

    if (name === 'toggleDeveloperMode') {
       return { success: true, message: 'Mode switched' };
    }

    return { error: 'Unknown tool' };
  }, []);

  const { connect, disconnect, connectionState, transcripts, volume } = useLiveSession({
    onToolCall: handleToolCall
  });

  const isConnected = connectionState === ConnectionState.CONNECTED;
  const isConnecting = connectionState === ConnectionState.CONNECTING;

