import React, { useState, useCallback } from 'react';
import { Mic, MicOff, Music, Search, Newspaper, ExternalLink, X, Maximize2 } from 'lucide-react';
import { useLiveSession } from './hooks/useLiveSession';
import Visualizer from './components/Visualizer';
import ChatInterface from './components/ChatInterface';
import { ConnectionState } from './types';

// State for showing what the assistant is currently doing
interface AssistantAction {
  type: 'music' | 'search' | 'info' | null;
  message: string | null;
  link?: string;
}

interface MusicState {
  videoId?: string;
  query?: string;
}

function App() {
  const [lastAction, setLastAction] = useState<AssistantAction>({ type: null, message: null });
  const [musicState, setMusicState] = useState<MusicState | null>(null);

  const handleToolCall = useCallback(async (name: string, args: any) => {
    console.log('Tool Call:', name, args);

    if (name === 'openWebsite') {
      const { url } = args;
      if (url) {
        window.open(url, '_blank', 'noopener,noreferrer');
        setLastAction({ type: 'info', message: `Opened website`, link: url });
        return { success: true, message: `Opened ${url}` };
      }
      return { success: false, message: 'No URL provided' };
    }

    if (name === 'searchGoogle') {
        const { query } = args;
        if (query) {
            const url = `https://www.google.com/search?q=${encodeURIComponent(query)}`;
            window.open(url, '_blank', 'noopener,noreferrer');
            setLastAction({ type: 'search', message: `Researched: ${query}`, link: url });
            return { success: true, message: `Searched Google for: ${query}` };
        }
        return { success: false, message: 'No query provided' };
    }

    if (name === 'playMusic') {
      const { query, videoId } = args;
      if (query || videoId) {
        // Clean query to remove quotes if present
        const cleanQuery = query ? query.replace(/["']/g, '') : 'Unknown Song';

        setMusicState({ 
            query: cleanQuery, 
            videoId: videoId 
        });

        setLastAction({ 
          type: 'music', 
          message: `Playing ${videoId ? 'Track' : cleanQuery}...`, 
        });

        // Auto-clear action message after a delay
        setTimeout(() => setLastAction({ type: null, message: null }), 5000);

        return { success: true, status: `Now playing music.` };
      }
      return { success: false, message: 'No song specified' };
    }

    if (name === 'stopMusic') {
        setMusicState(null);
        return { success: true, message: 'Music stopped' };
    }

    if (name === 'toggleDeveloperMode') {
       return { success: true, message: 'Mode switched' };
    }

    return { error: 'Unknown tool' };
  }, []);

  const { connect, disconnect, connectionState, transcripts, volume } = useLiveSession({
    onToolCall: handleToolCall
  });

  const isConnected = connectionState === ConnectionState.CONNECTED;
  const isConnecting = connectionState === ConnectionState.CONNECTING;

  const toggleConnection = () => {
    if (isConnected || isConnecting) {
      disconnect();
    } else {
      connect();
    }
  };

  // Determine the best Embed URL
  const getEmbedUrl = () => {
      if (!musicState) return '';

      // PRIORITY 1: Direct Video ID (Most Reliable)
      if (musicState.videoId) {
          return `https://www.youtube.com/embed/${musicState.videoId}?autoplay=1&playsinline=1&rel=0&modestbranding=1`;
      }

      // PRIORITY 2: Fallback Search (Can be flaky, depends on browser policy)
      // Note: We use 'no-referrer' in the iframe policy below to help this work
      return `https://www.youtube.com/embed?listType=search&list=${encodeURIComponent(musicState.query || '')}&autoplay=1&playsinline=1&rel=0&modestbranding=1`;
  };

  return (
    <div className="h-screen w-screen bg-[#09090b] text-zinc-100 flex flex-col relative overflow-hidden font-sans selection:bg-purple-500/30">

      {/* Background */}
      <div className="absolute inset-0 pointer-events-none z-0">
         <div className="absolute top-[-20%] left-[-10%] w-[800px] h-[800px] bg-blue-600/10 rounded-full blur-[120px] opacity-50 animate-pulse"></div>
         <div className="absolute bottom-[-20%] right-[-10%] w-[600px] h-[600px] bg-purple-600/10 rounded-full blur-[100px] opacity-50"></div>
      </div>

      {/* Main Layout */}
      <div className="relative z-10 flex flex-col md:flex-row h-full">

        {/* Left Section: Orb & Controls */}
        <div className="flex-1 md:flex-[0.4] flex flex-col items-center justify-center p-6 relative border-b md:border-b-0 md:border-r border-white/5 bg-zinc-950/20 backdrop-blur-sm">

           {/* Header */}
           <div className="absolute top-6 left-6 flex items-center gap-2">
             <div className="w-2 h-2 rounded-full bg-gradient-to-r from-cyan-400 to-purple-500 shadow-[0_0_10px_rgba(168,85,247,0.5)]"></div>
             <span className="font-bold tracking-widest text-sm text-transparent bg-clip-text bg-gradient-to-r from-white to-zinc-400">BLURRY AI</span>
           </div>

           <div className="flex-1 flex flex-col items-center justify-center w-full">
              <Visualizer volume={volume} active={isConnected} />

              <div className="mt-12 flex flex-col items-center gap-2">
                  <h2 className="text-2xl font-bold text-center bg-clip-text text-transparent bg-gradient-to-b from-white to-zinc-500 transition-all duration-500">
                    {isConnected ? (volume > 0.05 ? "Listening..." : "Online") : "Say \"Hello Assistant\""}
                  </h2>
                  <p className="text-xs text-zinc-500 font-mono tracking-wide">
                      {isConnected ? "Ask to Play Music • News • Research" : "Tap microphone to wake up"}
                  </p>
              </div>
           </div>

           {/* Mic Button */}
           <div className="mb-10">
              <button 
                onClick={toggleConnection}
                disabled={isConnecting}
                className={`group relative flex items-center justify-center w-20 h-20 rounded-full transition-all duration-500 ${
                  isConnected 
                    ? 'bg-red-500/10 border border-red-500/50 hover:bg-red-500/20 shadow-[0_0_30px_rgba(239,68,68,0.2)]' 
                    : 'bg-white text-black hover:scale-110 shadow-[0_0_40px_rgba(255,255,255,0.4)]'
                }`}
              >
                 {isConnecting ? (
                     <div className="w-8 h-8 border-2 border-zinc-500 border-t-transparent rounded-full animate-spin"></div>
                 ) : isConnected ? (
                     <MicOff className="w-8 h-8 text-red-500 transition-transform group-hover:scale-110" />
                 ) : (
                     <Mic className="w-8 h-8 transition-transform group-hover:scale-110" />
                 )}
              </button>
           </div>
        </div>

        {/* Right Section: Content */}
        <div className="flex-1 md:flex-[0.6] flex flex-col bg-zinc-950/40 backdrop-blur-md relative shadow-2xl">

           {/* Chat */}
           <ChatInterface messages={transcripts} />

           {/* In-App Music Player Embed */}
           {musicState && (
               <div className="absolute bottom-24 right-4 md:right-8 w-[90%] md:w-96 h-64 bg-black rounded-2xl overflow-hidden shadow-[0_0_40px_rgba(0,0,0,0.5)] z-50 border border-zinc-800 animate-in slide-in-from-bottom-20 ring-1 ring-white/10 flex flex-col">
                  {/* Player Header */}
                  <div className="bg-zinc-900/90 backdrop-blur px-4 py-3 flex justify-between items-center border-b border-white/5 shrink-0">
                     <div className="flex items-center gap-2">
                        <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                        <span className="text-xs font-bold text-zinc-300 truncate max-w-[150px] uppercase tracking-wider">
                            {musicState.videoId ? 'Direct Play' : `Search: ${musicState.query}`}
                        </span>
                     </div>
                     <button 
                        onClick={() => setMusicState(null)}
                        className="p-1.5 hover:bg-white/10 rounded-full transition-colors"
                     >
                        <X size={14} className="text-zinc-400" />
                     </button>
                  </div>

                  {/* Embed Container */}
                  <div className="flex-1 relative bg-black">
                      <iframe
                        width="100%"
                        height="100%"
                        src={getEmbedUrl()}
                        title="Music Player"
                        frameBorder="0"
                        referrerPolicy="no-referrer"
                        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
                        allowFullScreen
                        className="absolute inset-0 w-full h-full" 
                      ></iframe>
                  </div>
               </div>
           )}

           {/* HUD / Notification Toast for External Actions */}
           {lastAction.message && (
             <div className="absolute bottom-8 left-1/2 -translate-x-1/2 w-[90%] md:w-auto bg-zinc-900/95 border border-zinc-700/50 backdrop-blur-xl px-6 py-4 rounded-full flex items-center gap-4 shadow-2xl z-40 animate-in slide-in-from-bottom-10 ring-1 ring-white/10">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center shrink-0 ${
                    lastAction.type === 'music' ? 'bg-pink-500/20 text-pink-500' : 'bg-blue-500/20 text-blue-500'
                }`}>
                   {lastAction.type === 'music' ? <Music size={20} /> : <Search size={20} />}
                </div>
                <div className="flex-1 min-w-0 pr-2">
                   <p className="text-sm font-medium text-white truncate">{lastAction.message}</p>
                   {lastAction.link && (
                       <p className="text-[10px] text-zinc-500 truncate">{new URL(lastAction.link).hostname}</p>
                   )}
                </div>
                {lastAction.link && (
                    <a href={lastAction.link} target="_blank" rel="noreferrer" className="p-2 hover:bg-white/10 rounded-full transition-colors">
                        <ExternalLink size={16} className="text-zinc-400" />
                    </a>
                )}
             </div>
           )}

           {/* Quick Suggestion Chips */}
           {!isConnected && transcripts.length === 0 && (
             <div className="absolute bottom-8 left-0 w-full px-8 overflow-x-auto no-scrollbar flex gap-3 justify-center">
                <button 
                  onClick={toggleConnection}
                  className="flex items-center gap-2 px-5 py-2.5 rounded-full bg-zinc-800/80 border border-zinc-700/50 text-xs font-medium text-zinc-300 hover:bg-white hover:text-black transition-all"
                >
                    <Music size={14} /> "Play Arjit Singh"
                </button>
                <button 
                  onClick={toggleConnection}
                  className="flex items-center gap-2 px-5 py-2.5 rounded-full bg-zinc-800/80 border border-zinc-700/50 text-xs font-medium text-zinc-300 hover:bg-white hover:text-black transition-all"
                >
                    <Newspaper size={14} /> "Latest News"
                </button>
                <button 
                  onClick={toggleConnection}
                  className="flex items-center gap-2 px-5 py-2.5 rounded-full bg-zinc-800/80 border border-zinc-700/50 text-xs font-medium text-zinc-300 hover:bg-white hover:text-black transition-all"
                >
                    <Search size={14} /> "Research React"
                </button>
             </div>
           )}

        </div>

      </div>
    </div>
  );
}

export default App;

import React, { useState, useCallback } from 'react';
import { Mic, MicOff, Music, Search, Newspaper, ExternalLink, X, Maximize2, Loader2 } from 'lucide-react';
import { useLiveSession } from './hooks/useLiveSession';
import Visualizer from './components/Visualizer';
import ChatInterface from './components/ChatInterface';
import { ConnectionState } from './types';

// State for showing what the assistant is currently doing
interface AssistantAction {
  type: 'music' | 'search' | 'info' | null;
  message: string | null;
  link?: string;
}

interface MusicState {
  videoId?: string;
  query?: string;
  title?: string;
  isLoading?: boolean;
}

function App() {
  const [lastAction, setLastAction] = useState<AssistantAction>({ type: null, message: null });
  const [musicState, setMusicState] = useState<MusicState | null>(null);

  const handleToolCall = useCallback(async (name: string, args: any) => {
    console.log('Tool Call:', name, args);

    if (name === 'openWebsite') {
      const { url } = args;
      if (url) {
        window.open(url, '_blank', 'noopener,noreferrer');
        setLastAction({ type: 'info', message: `Opened website`, link: url });
        return { success: true, message: `Opened ${url}` };
      }
      return { success: false, message: 'No URL provided' };
    }

    if (name === 'searchGoogle') {
        const { query } = args;
        if (query) {
            const url = `https://www.google.com/search?q=${encodeURIComponent(query)}`;
            window.open(url, '_blank', 'noopener,noreferrer');
            setLastAction({ type: 'search', message: `Researched: ${query}`, link: url });
            return { success: true, message: `Searched Google for: ${query}` };
        }
        return { success: false, message: 'No query provided' };
    }

    if (name === 'playMusic') {
      const { query, videoId } = args;

      // Case 1: AI provided a direct Video ID (Best case)
      if (videoId) {
          setMusicState({ videoId, title: 'Direct Play', isLoading: false });
          setLastAction({ type: 'music', message: `Playing Track...` });
          setTimeout(() => setLastAction({ type: null, message: null }), 5000);
          return { success: true, status: `Playing video ID: ${videoId}` };
      }

      // Case 2: AI provided a query, we need to resolve it to an ID (Alternative Logic)
      if (query) {
        const cleanQuery = query.replace(/["']/g, '');
        setMusicState({ query: cleanQuery, isLoading: true });
        setLastAction({ type: 'music', message: `Searching: ${cleanQuery}...` });

        try {
            // Alternative Logic: Resolve ID using Piped API (Public YouTube frontend API)
            // This avoids the unreliable 'listType=search' embed parameter.
            const response = await fetch(`https://pipedapi.kavin.rocks/search?q=${encodeURIComponent(cleanQuery)}&filter=all`);
            const data = await response.json();

            if (data.items && data.items.length > 0) {
                // Find the first actual stream (video), skipping channels/playlists
                const firstVideo = data.items.find((item: any) => item.type === 'stream');

                if (firstVideo) {
                    const fetchedId = firstVideo.url.split('v=')[1];
                    setMusicState({ 
                        videoId: fetchedId, 
                        query: cleanQuery, 
                        title: firstVideo.title,
                        isLoading: false 
                    });
                    setLastAction({ type: 'music', message: `Found: ${firstVideo.title}` });
                    setTimeout(() => setLastAction({ type: null, message: null }), 5000);
                    return { success: true, message: `Playing ${firstVideo.title}` };
                }
            }
            throw new Error("No videos found");
        } catch (error) {
            console.error("Music search failed, falling back to legacy embed", error);
            // Fallback: If API fails, try the legacy search embed but warn user it might be flaky
            setMusicState({ query: cleanQuery, isLoading: false }); 
            setLastAction({ type: 'music', message: `Playing Search Result` });
            return { success: true, message: `Playing search for ${cleanQuery}` };
        }
      }
      return { success: false, message: 'No song specified' };
    }

    if (name === 'stopMusic') {
        setMusicState(null);
        return { success: true, message: 'Music stopped' };
    }

    if (name === 'toggleDeveloperMode') {
       return { success: true, message: 'Mode switched' };
    }

    return { error: 'Unknown tool' };
  }, []);

  const { connect, disconnect, connectionState, transcripts, volume } = useLiveSession({
    onToolCall: handleToolCall
  });

  const isConnected = connectionState === ConnectionState.CONNECTED;
  const isConnecting = connectionState === ConnectionState.CONNECTING;

  const toggleConnection = () => {
    if (isConnected || isConnecting) {
      disconnect();
    } else {
      connect();
    }
  };

  // Determine the best Embed URL
  const getEmbedUrl = () => {
      if (!musicState) return '';

      // PRIORITY 1: Direct Video ID (Resolved via API or provided by AI)
      if (musicState.videoId) {
          return `https://www.youtube.com/embed/${musicState.videoId}?autoplay=1&playsinline=1&rel=0&modestbranding=1`;
      }

      // PRIORITY 2: Fallback Search (Only if API failed)
      return `https://www.youtube.com/embed?listType=search&list=${encodeURIComponent(musicState.query || '')}&autoplay=1&playsinline=1&rel=0&modestbranding=1`;
  };

  return (
    <div className="h-screen w-screen bg-[#09090b] text-zinc-100 flex flex-col relative overflow-hidden font-sans selection:bg-purple-500/30">

      {/* Background */}
      <div className="absolute inset-0 pointer-events-none z-0">
         <div className="absolute top-[-20%] left-[-10%] w-[800px] h-[800px] bg-blue-600/10 rounded-full blur-[120px] opacity-50 animate-pulse"></div>
         <div className="absolute bottom-[-20%] right-[-10%] w-[600px] h-[600px] bg-purple-600/10 rounded-full blur-[100px] opacity-50"></div>
      </div>

      {/* Main Layout */}
      <div className="relative z-10 flex flex-col md:flex-row h-full">

        {/* Left Section: Orb & Controls */}
        <div className="flex-1 md:flex-[0.4] flex flex-col items-center justify-center p-6 relative border-b md:border-b-0 md:border-r border-white/5 bg-zinc-950/20 backdrop-blur-sm">

           {/* Header */}
           <div className="absolute top-6 left-6 flex items-center gap-2">
             <div className="w-2 h-2 rounded-full bg-gradient-to-r from-cyan-400 to-purple-500 shadow-[0_0_10px_rgba(168,85,247,0.5)]"></div>
             <span className="font-bold tracking-widest text-sm text-transparent bg-clip-text bg-gradient-to-r from-white to-zinc-400">BLURRY AI</span>
           </div>

           <div className="flex-1 flex flex-col items-center justify-center w-full">
              <Visualizer volume={volume} active={isConnected} />

              <div className="mt-12 flex flex-col items-center gap-2">
                  <h2 className="text-2xl font-bold text-center bg-clip-text text-transparent bg-gradient-to-b from-white to-zinc-500 transition-all duration-500">
                    {isConnected ? (volume > 0.05 ? "Listening..." : "Online") : "Say \"Hello Assistant\""}
                  </h2>
                  <p className="text-xs text-zinc-500 font-mono tracking-wide">
                      {isConnected ? "Ask to Play Music • News • Research" : "Tap microphone to wake up"}
                  </p>
              </div>
           </div>

           {/* Mic Button */}
           <div className="mb-10">
              <button 
                onClick={toggleConnection}
                disabled={isConnecting}
                className={`group relative flex items-center justify-center w-20 h-20 rounded-full transition-all duration-500 ${
                  isConnected 
                    ? 'bg-red-500/10 border border-red-500/50 hover:bg-red-500/20 shadow-[0_0_30px_rgba(239,68,68,0.2)]' 
                    : 'bg-white text-black hover:scale-110 shadow-[0_0_40px_rgba(255,255,255,0.4)]'
                }`}
              >
                 {isConnecting ? (
                     <div className="w-8 h-8 border-2 border-zinc-500 border-t-transparent rounded-full animate-spin"></div>
                 ) : isConnected ? (
                     <MicOff className="w-8 h-8 text-red-500 transition-transform group-hover:scale-110" />
                 ) : (
                     <Mic className="w-8 h-8 transition-transform group-hover:scale-110" />
                 )}
              </button>
           </div>
        </div>

        {/* Right Section: Content */}
        <div className="flex-1 md:flex-[0.6] flex flex-col bg-zinc-950/40 backdrop-blur-md relative shadow-2xl">

           {/* Chat */}
           <ChatInterface messages={transcripts} />

           {/* In-App Music Player Embed */}
           {musicState && (
               <div className="absolute bottom-24 right-4 md:right-8 w-[90%] md:w-96 h-64 bg-black rounded-2xl overflow-hidden shadow-[0_0_40px_rgba(0,0,0,0.5)] z-50 border border-zinc-800 animate-in slide-in-from-bottom-20 ring-1 ring-white/10 flex flex-col">
                  {/* Player Header */}
                  <div className="bg-zinc-900/90 backdrop-blur px-4 py-3 flex justify-between items-center border-b border-white/5 shrink-0">
                     <div className="flex items-center gap-2">
                        <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                        <span className="text-xs font-bold text-zinc-300 truncate max-w-[150px] uppercase tracking-wider">
                            {musicState.isLoading ? 'Searching...' : (musicState.title || musicState.query || 'Music')}
                        </span>
                     </div>
                     <button 
                        onClick={() => setMusicState(null)}
                        className="p-1.5 hover:bg-white/10 rounded-full transition-colors"
                     >
                        <X size={14} className="text-zinc-400" />
                     </button>
                  </div>

                  {/* Embed Container */}
                  <div className="flex-1 relative bg-black flex items-center justify-center">
                      {musicState.isLoading ? (
                          <div className="flex flex-col items-center gap-2 text-zinc-500">
