                   )}
                </div>
                {lastAction.link && (
                    <a href={lastAction.link} target="_blank" rel="noreferrer" className="p-2 hover:bg-white/10 rounded-full transition-colors">
                        <ExternalLink size={16} className="text-zinc-400" />
                    </a>
                )}
             </div>
           )}

           {/* Quick Suggestion Chips */}
           {!isConnected && transcripts.length === 0 && (
             <div className="absolute bottom-8 left-0 w-full px-8 overflow-x-auto no-scrollbar flex gap-3 justify-center">
                <button 
                  onClick={toggleConnection}
                  className="flex items-center gap-2 px-5 py-2.5 rounded-full bg-zinc-800/80 border border-zinc-700/50 text-xs font-medium text-zinc-300 hover:bg-white hover:text-black transition-all"
                >
                    <Music size={14} /> "Play Arjit Singh"
                </button>
