// State for showing what the assistant is currently doing
interface AssistantAction {
  type: 'music' | 'search' | 'info' | null;
  message: string | null;
  link?: string;
}

interface MusicState {
  videoId?: string;
  query?: string;
  title?: string;
  isLoading?: boolean;
  error?: boolean;
}

// EXPANDED: Massive list of public instances to rotate through
const SEARCH_INSTANCES = [
  "https://pipedapi.kavin.rocks",
  "https://api.piped.ot.ax",
  "https://pipedapi.tokhmi.xyz",
  "https://api.piped.privacy.com.de",
  "https://pipedapi.adminforge.de",
  "https://api.piped.drgns.space",
  "https://pipedapi.r4fo.com",
  "https://piped-api.lunar.icu",
  "https://pipedapi.smnz.de",
  "https://api.piped.projectsegfau.lt",
  "https://pipedapi.mha.fi",
  "https://api.piped.yt.im",
  "https://pipedapi.ducks.party",
  "https://inv.tux.pizza/api/v1",
  "https://vid.puffyan.us/api/v1",
  "https://invidious.projectsegfau.lt/api/v1"
];

const findVideoId = async (query: string): Promise<{ id: string, title: string } | null> => {
    for (const instance of SEARCH_INSTANCES) {
        try {
            const isInvidious = instance.includes('/api/v1');
            const searchUrl = isInvidious 
                ? `${instance}/search?q=${encodeURIComponent(query)}` 
                : `${instance}/search?q=${encodeURIComponent(query)}&filter=videos`;

            const controller = new AbortController();
            const timeoutId = setTimeout(() => controller.abort(), 2000); // 2s timeout

            const res = await fetch(searchUrl, { signal: controller.signal });
            clearTimeout(timeoutId);

            if (!res.ok) continue;

            const data = await res.json();

            if (isInvidious) {
                const item = Array.isArray(data) ? data.find((i: any) => i.type === 'video') : null;
                if (item?.videoId) return { id: item.videoId, title: item.title };
            } else {
                const item = data.items?.find((i: any) => i.type === 'stream');
                if (item?.url) return { id: item.url.split('v=')[1], title: item.title };
            }
        } catch (e) {
            // Silently fail and try next
        }
    }
    return null;
}

function App() {
  const [lastAction, setLastAction] = useState<AssistantAction>({ type: null, message: null });
  const [musicState, setMusicState] = useState<MusicState | null>(null);
  const [showSettings, setShowSettings] = useState(false);

  // Load settings from localStorage
  const [settings, setSettings] = useState<AppSettings>(() => ({
    apiKey: localStorage.getItem('user_api_key') || '',
    model: localStorage.getItem('user_model') || 'gemini-2.5-flash-native-audio-preview-09-2025',
    baseUrl: localStorage.getItem('user_base_url') || '',
  }));

  const saveSettings = (newSettings: AppSettings) => {
      localStorage.setItem('user_api_key', newSettings.apiKey);
      localStorage.setItem('user_model', newSettings.model);
      localStorage.setItem('user_base_url', newSettings.baseUrl);
      setSettings(newSettings);
      setShowSettings(false);
  };

  const handleToolCall = useCallback(async (name: string, args: any) => {
    console.log('Tool Call:', name, args);

    if (name === 'openWebsite') {
      const { url } = args;
      if (url) {
        window.open(url, '_blank', 'noopener,noreferrer');
        setLastAction({ type: 'info', message: `Opened website`, link: url });
        return { success: true, message: `Opened ${url}` };
      }
      return { success: false, message: 'No URL provided' };
    }

    if (name === 'searchGoogle') {
        const { query } = args;
        if (query) {
            const url = `https://www.google.com/search?q=${encodeURIComponent(query)}`;
            window.open(url, '_blank', 'noopener,noreferrer');
            setLastAction({ type: 'search', message: `Researched: ${query}`, link: url });
            return { success: true, message: `Searched Google for: ${query}` };
        }
        return { success: false, message: 'No query provided' };
    }

    if (name === 'playMusic') {
      const { query, videoId } = args;

      if (videoId) {
          setMusicState({ videoId, title: 'Direct Play', isLoading: false, error: false });
          setLastAction({ type: 'music', message: `Playing Track...` });
          setTimeout(() => setLastAction({ type: null, message: null }), 5000);
          return { success: true, status: `Playing video ID: ${videoId}` };
      }

      if (query) {
        const cleanQuery = query.replace(/["']/g, '');
        setMusicState({ query: cleanQuery, isLoading: true, error: false });
        setLastAction({ type: 'music', message: `Searching: ${cleanQuery}...` });

        findVideoId(cleanQuery).then((result) => {
            if (result) {
                setMusicState({ 
                    videoId: result.id, 
                    query: cleanQuery, 
                    title: result.title, 
                    isLoading: false,
                    error: false
                });
                setLastAction({ type: 'music', message: `Found: ${result.title}` });
            } else {
                // If all fails, show the fallback UI without throwing an error
                setMusicState({ 
                    query: cleanQuery, 
                    isLoading: false,
                    error: true 
                });
                setLastAction({ type: 'music', message: `Click to play on YouTube` });
            }
            setTimeout(() => setLastAction({ type: null, message: null }), 5000);
        });

        return { success: true, message: `Searching for ${cleanQuery}` };
      }
      return { success: false, message: 'No song specified' };
    }

    if (name === 'stopMusic') {
        setMusicState(null);
        return { success: true, message: 'Music stopped' };
    }

    if (name === 'toggleDeveloperMode') {
       return { success: true, message: 'Mode switched' };
    }

    return { error: 'Unknown tool' };
  }, []);

  const { connect, disconnect, connectionState, transcripts, volume } = useLiveSession({
    onToolCall: handleToolCall,
    settings
  });

  const isConnected = connectionState === ConnectionState.CONNECTED;
  const isConnecting = connectionState === ConnectionState.CONNECTING;

  const toggleConnection = () => {
