import { useState, useRef, useEffect, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";
import { SYSTEM_INSTRUCTION, tools } from '../constants';
import { createPcmBlob, decodeAudioData, base64ToUint8Array, downsampleBuffer } from '../utils/audio';
import { ConnectionState, Message, AppSettings } from '../types';

interface UseLiveSessionProps {
  onToolCall?: (name: string, args: any) => Promise<any>;
  settings: AppSettings;
}

export const useLiveSession = ({ onToolCall, settings }: UseLiveSessionProps) => {
  const [connectionState, setConnectionState] = useState<ConnectionState>(ConnectionState.DISCONNECTED);
  const [transcripts, setTranscripts] = useState<Message[]>([]);
  const [volume, setVolume] = useState<number>(0);

  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const outputContextRef = useRef<AudioContext | null>(null);
  const inputSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const analyserRef = useRef<AnalyserNode | null>(null);

  // Use Ref for onToolCall to avoid stale closures
  const onToolCallRef = useRef(onToolCall);
  useEffect(() => {
    onToolCallRef.current = onToolCall;
  }, [onToolCall]);

  const currentInputRef = useRef<string>('');
  const currentOutputRef = useRef<string>('');
  const isUserSpeakingRef = useRef<boolean>(false);

  const addTranscript = useCallback((role: 'user' | 'assistant' | 'system', text: string, isFinal: boolean = true) => {
    setTranscripts(prev => {
      if (!isFinal && prev.length > 0 && prev[prev.length - 1].role === role && (Date.now() - prev[prev.length - 1].timestamp.getTime() < 5000)) {
         const newArr = [...prev];
         newArr[newArr.length - 1] = { ...newArr[newArr.length - 1], text };
         return newArr;
      }
      return [...prev, { id: Date.now().toString() + Math.random(), role, text, timestamp: new Date() }];
    });
  }, []);

  const cleanupAudio = useCallback(async () => {
    if (processorRef.current) {
        processorRef.current.disconnect();
        processorRef.current = null;
    }
    if (inputSourceRef.current) {
        inputSourceRef.current.disconnect();
        inputSourceRef.current = null;
    }
    if (inputContextRef.current) {
        try { await inputContextRef.current.close(); } catch(e) {}
        inputContextRef.current = null;
    }
    if (outputContextRef.current) {
        try { await outputContextRef.current.close(); } catch(e) {}
        outputContextRef.current = null;
    }
    audioSourcesRef.current.forEach(source => {
        try { source.stop(); } catch (e) {}
    });
    audioSourcesRef.current.clear();
    sessionPromiseRef.current = null;
    setVolume(0);
    currentInputRef.current = '';
    currentOutputRef.current = '';
  }, []);

  const connect = useCallback(async () => {
    const activeApiKey = settings.apiKey || process.env.API_KEY;

    if (!activeApiKey) {
      addTranscript('system', 'Error: API Key is missing. Please check settings.');
      setConnectionState(ConnectionState.ERROR);
      return;
    }

    if (connectionState === ConnectionState.CONNECTED || connectionState === ConnectionState.CONNECTING) {
        return;
    }

    try {
      setConnectionState(ConnectionState.CONNECTING);

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)();

      if (inputCtx.state === 'suspended') await inputCtx.resume();
      if (outputCtx.state === 'suspended') await outputCtx.resume();

      inputContextRef.current = inputCtx;
      outputContextRef.current = outputCtx;

      const analyser = outputCtx.createAnalyser();
      analyser.fftSize = 256;
      analyserRef.current = analyser;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const source = inputCtx.createMediaStreamSource(stream);
      inputSourceRef.current = source;

      const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
      processorRef.current = scriptProcessor;

      const clientOptions: any = { apiKey: activeApiKey };
      if (settings.baseUrl) {
          clientOptions.baseUrl = settings.baseUrl; 
      }

      const ai = new GoogleGenAI(clientOptions);

      // Determine System Instruction
      const instructions = settings.systemInstruction?.trim() 
        ? settings.systemInstruction 
        : SYSTEM_INSTRUCTION;

      const sessionPromise = ai.live.connect({
        model: settings.model || 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: { parts: [{ text: instructions }] },
          tools: [{ functionDeclarations: tools }],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: settings.voiceName || 'Kore' } }
          },
          inputAudioTranscription: {}, 
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log('Session connected');
            setConnectionState(ConnectionState.CONNECTED);
            addTranscript('system', 'Voice Assistant Connected.');

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputCtx.destination);

            scriptProcessor.onaudioprocess = (e) => {
              if (!sessionPromiseRef.current) return;

              const inputData = e.inputBuffer.getChannelData(0);

              let sum = 0;
              for (let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
              const rms = Math.sqrt(sum / inputData.length);
              setVolume(v => (v * 0.8) + (rms * 2)); 

              const downsampledData = downsampleBuffer(inputData, inputCtx.sampleRate, 16000);
              const pcmBlob = createPcmBlob(downsampledData, 16000);

              sessionPromiseRef.current.then(session => {
                  try {
                    session.sendRealtimeInput({ media: pcmBlob });
                  } catch (e) {
                  }
              });
            };
          },
          onmessage: async (message: LiveServerMessage) => {
            const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData) {
              const ctx = outputContextRef.current;
              if (ctx && ctx.state !== 'closed') {
                 nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
                 const audioBuffer = await decodeAudioData(base64ToUint8Array(audioData), ctx, 24000, 1);
                 const source = ctx.createBufferSource();
                 source.buffer = audioBuffer;
                 if (analyserRef.current) {
                    source.connect(analyserRef.current);
                    analyserRef.current.connect(ctx.destination);
                 } else {
                    source.connect(ctx.destination);
                 }
                 source.addEventListener('ended', () => audioSourcesRef.current.delete(source));
                 source.start(nextStartTimeRef.current);
                 audioSourcesRef.current.add(source);
                 nextStartTimeRef.current += audioBuffer.duration;
              }
            }

            const inputTranscript = message.serverContent?.inputTranscription?.text;
            if (inputTranscript) {
               currentInputRef.current += inputTranscript;
               addTranscript('user', currentInputRef.current, false);
            }

            const outputTranscript = message.serverContent?.outputTranscription?.text;
            if (outputTranscript) {
               currentOutputRef.current += outputTranscript;
               addTranscript('assistant', currentOutputRef.current, false);
            }

            if (message.serverContent?.turnComplete) {
               isUserSpeakingRef.current = !isUserSpeakingRef.current;
               if (currentInputRef.current) {
                   addTranscript('user', currentInputRef.current, true);
                   currentInputRef.current = '';
               }
               if (currentOutputRef.current) {
                   addTranscript('assistant', currentOutputRef.current, true);
                   currentOutputRef.current = '';
               }
            }

            if (message.toolCall) {
                addTranscript('system', 'Processing request...', true);
                for (const fc of message.toolCall.functionCalls) {
                    let result: any = { result: 'Success' };
                    if (onToolCallRef.current) {
                       try {
                           result = await onToolCallRef.current(fc.name, fc.args);
                           addTranscript('system', `Executed: ${fc.name}`, true);
                       } catch (e) {
                           result = { error: 'Failed' };
                       }
                    }
                    if (sessionPromiseRef.current) {
                        sessionPromiseRef.current.then(session => {
                            session.sendToolResponse({
                                functionResponses: {
                                    id: fc.id,
                                    name: fc.name,
                                    response: result
                                }
                            });
                        });
                    }
                }
            }
          },
          onclose: () => {
            setConnectionState(ConnectionState.DISCONNECTED);
            cleanupAudio();
          },
          onerror: (err) => {
            console.error("Live Session Error:", err instanceof Error ? err.message : "Unknown error");
            setConnectionState(ConnectionState.ERROR);
            cleanupAudio();
          }
        }
      });
      sessionPromiseRef.current = sessionPromise;

    } catch (error) {
      console.error(error);
      setConnectionState(ConnectionState.ERROR);
      cleanupAudio();
    }
  }, [addTranscript, connectionState, cleanupAudio, settings]);

  const disconnect = useCallback(async () => {
    if (sessionPromiseRef.current) {
       const session = await sessionPromiseRef.current;
       try { (session as any).close(); } catch (e) {}
    }
    await cleanupAudio();
    setConnectionState(ConnectionState.DISCONNECTED);
  }, [cleanupAudio]);

  useEffect(() => {
    let animationFrame: number;
    const updateOutputVolume = () => {
        if (analyserRef.current) {
            const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
            analyserRef.current.getByteFrequencyData(dataArray);
            let sum = 0;
            for(let i=0; i<dataArray.length; i++) sum += dataArray[i];
            const avg = sum / dataArray.length;
            const norm = avg / 255; 
            if (norm > 0.01) {
                setVolume(prev => (prev * 0.5) + (norm * 0.5));
            }
        }
        animationFrame = requestAnimationFrame(updateOutputVolume);
    };
    updateOutputVolume();
    return () => cancelAnimationFrame(animationFrame);
  }, []);

  return { connect, disconnect, connectionState, transcripts, volume };
};

import React, { useState, useCallback } from 'react';
import { Mic, MicOff, Settings as SettingsIcon } from 'lucide-react';
import { useLiveSession } from './hooks/useLiveSession';
import Visualizer from './components/Visualizer';
import ChatInterface from './components/ChatInterface';
import SettingsModal from './components/SettingsModal';
import MusicPlayer from './components/MusicPlayer';
import ActionHUD from './components/ActionHUD';
import QuickSuggestions from './components/QuickSuggestions';
import { findVideoId } from './utils/search';
import { ConnectionState, AppSettings, AssistantAction, MusicState } from './types';
import { SYSTEM_INSTRUCTION } from './constants';

function App() {
  const [lastAction, setLastAction] = useState<AssistantAction>({ type: null, message: null });
  const [musicState, setMusicState] = useState<MusicState | null>(null);
  const [showSettings, setShowSettings] = useState(false);

  // Load settings from localStorage with new defaults
  const [settings, setSettings] = useState<AppSettings>(() => ({
    apiKey: localStorage.getItem('user_api_key') || '',
    model: localStorage.getItem('user_model') || 'gemini-2.5-flash-native-audio-preview-09-2025',
    baseUrl: localStorage.getItem('user_base_url') || '',
    voiceName: localStorage.getItem('user_voice') || 'Kore',
    systemInstruction: localStorage.getItem('user_system_instruction') || SYSTEM_INSTRUCTION
  }));

  const saveSettings = (newSettings: AppSettings) => {
      localStorage.setItem('user_api_key', newSettings.apiKey);
      localStorage.setItem('user_model', newSettings.model);
      localStorage.setItem('user_base_url', newSettings.baseUrl);
      localStorage.setItem('user_voice', newSettings.voiceName);
      localStorage.setItem('user_system_instruction', newSettings.systemInstruction);
      setSettings(newSettings);
      setShowSettings(false);
  };

  const handleToolCall = useCallback(async (name: string, args: any) => {
    console.log('Tool Call:', name, args);

    if (name === 'openWebsite') {
      const { url } = args;
      if (url) {
        window.open(url, '_blank', 'noopener,noreferrer');
        setLastAction({ type: 'info', message: `Opened website`, link: url });
        return { success: true, message: `Opened ${url}` };
      }
      return { success: false, message: 'No URL provided' };
    }

    if (name === 'searchGoogle') {
        const { query } = args;
        if (query) {
            const url = `https://www.google.com/search?q=${encodeURIComponent(query)}`;
            window.open(url, '_blank', 'noopener,noreferrer');
            setLastAction({ type: 'search', message: `Researched: ${query}`, link: url });
            return { success: true, message: `Searched Google for: ${query}` };
        }
        return { success: false, message: 'No query provided' };
    }

    if (name === 'playMusic') {
      const { query, videoId } = args;

      if (videoId) {
          setMusicState({ videoId, title: 'Direct Play', isLoading: false, error: false });
          setLastAction({ type: 'music', message: `Playing Track...` });
          setTimeout(() => setLastAction({ type: null, message: null }), 5000);
          return { success: true, status: `Playing video ID: ${videoId}` };
      }

      if (query) {
        const cleanQuery = query.replace(/["']/g, '');
        setMusicState({ query: cleanQuery, isLoading: true, error: false });
        setLastAction({ type: 'music', message: `Searching: ${cleanQuery}...` });

        findVideoId(cleanQuery).then((result) => {
            if (result) {
                setMusicState({ 
                    videoId: result.id, 
                    query: cleanQuery, 
                    title: result.title, 
                    isLoading: false,
                    error: false
                });
                setLastAction({ type: 'music', message: `Found: ${result.title}` });
            } else {
                setMusicState({ 
                    query: cleanQuery, 
                    isLoading: false,
                    error: true 
                });
                setLastAction({ type: 'music', message: `Click to play on YouTube` });
            }
            setTimeout(() => setLastAction({ type: null, message: null }), 5000);
        });

        return { success: true, message: `Searching for ${cleanQuery}` };
      }
      return { success: false, message: 'No song specified' };
    }

    if (name === 'stopMusic') {
        setMusicState(null);
        return { success: true, message: 'Music stopped' };
    }

    return { error: 'Unknown tool' };
  }, []);

  const { connect, disconnect, connectionState, transcripts, volume } = useLiveSession({
    onToolCall: handleToolCall,
    settings
  });

  const isConnected = connectionState === ConnectionState.CONNECTED;
  const isConnecting = connectionState === ConnectionState.CONNECTING;

  const toggleConnection = () => {
    if (isConnected || isConnecting) {
      disconnect();
    } else {
      connect();
    }
  };

  return (
    <div className="h-screen w-screen bg-[#09090b] text-zinc-100 flex flex-col relative overflow-hidden font-sans selection:bg-purple-500/30">

      {/* Background */}
      <div className="absolute inset-0 pointer-events-none z-0">
         <div className="absolute top-[-20%] left-[-10%] w-[800px] h-[800px] bg-blue-600/10 rounded-full blur-[120px] opacity-50 animate-pulse"></div>
         <div className="absolute bottom-[-20%] right-[-10%] w-[600px] h-[600px] bg-purple-600/10 rounded-full blur-[100px] opacity-50"></div>
      </div>

      {/* Main Layout */}
      <div className="relative z-10 flex flex-col md:flex-row h-full">

        {/* Left Section: Orb & Controls */}
        <div className="flex-1 md:flex-[0.4] flex flex-col items-center justify-center p-6 relative border-b md:border-b-0 md:border-r border-white/5 bg-zinc-950/20 backdrop-blur-sm">

           {/* Header */}
           <div className="absolute top-6 left-6 flex items-center gap-2">
             <div className="w-2 h-2 rounded-full bg-gradient-to-r from-cyan-400 to-purple-500 shadow-[0_0_10px_rgba(168,85,247,0.5)]"></div>
             <span className="font-bold tracking-widest text-sm text-transparent bg-clip-text bg-gradient-to-r from-white to-zinc-400">BLURRY AI</span>
           </div>

           {/* Settings Button */}
           <button 
             onClick={() => setShowSettings(true)}
             className="absolute top-6 right-6 p-2 text-zinc-500 hover:text-white hover:bg-white/10 rounded-full transition-all"
           >
             <SettingsIcon size={20} />
           </button>

           <div className="flex-1 flex flex-col items-center justify-center w-full">
              <Visualizer volume={volume} active={isConnected} />

              <div className="mt-12 flex flex-col items-center gap-2">
                  <h2 className="text-2xl font-bold text-center bg-clip-text text-transparent bg-gradient-to-b from-white to-zinc-500 transition-all duration-500">
                    {isConnected ? (volume > 0.05 ? "Listening..." : "Online") : "Say \"Hello Assistant\""}
                  </h2>
                  <p className="text-xs text-zinc-500 font-mono tracking-wide">
                      {isConnected ? "Ask to Play Music • News • Research" : "Tap microphone to wake up"}
                  </p>
              </div>
           </div>

           {/* Mic Button */}
           <div className="mb-10">
              <button 
                onClick={toggleConnection}
                disabled={isConnecting}
                className={`group relative flex items-center justify-center w-20 h-20 rounded-full transition-all duration-500 ${
                  isConnected 
                    ? 'bg-red-500/10 border border-red-500/50 hover:bg-red-500/20 shadow-[0_0_30px_rgba(239,68,68,0.2)]' 
                    : 'bg-white text-black hover:scale-110 shadow-[0_0_40px_rgba(255,255,255,0.4)]'
                }`}
              >
                 {isConnecting ? (
                     <div className="w-8 h-8 border-2 border-zinc-500 border-t-transparent rounded-full animate-spin"></div>
                 ) : isConnected ? (
                     <MicOff className="w-8 h-8 text-red-500 transition-transform group-hover:scale-110" />
                 ) : (
                     <Mic className="w-8 h-8 transition-transform group-hover:scale-110" />
                 )}
              </button>
           </div>
        </div>

        {/* Right Section: Content */}
        <div className="flex-1 md:flex-[0.6] flex flex-col bg-zinc-950/40 backdrop-blur-md relative shadow-2xl">

           <ChatInterface messages={transcripts} />

           <MusicPlayer musicState={musicState} onClose={() => setMusicState(null)} />

           <ActionHUD action={lastAction} />

           <QuickSuggestions 
              visible={!isConnected && transcripts.length === 0} 
              onConnect={toggleConnection} 
           />

        </div>
      </div>

      <SettingsModal 
        isOpen={showSettings} 
        onClose={() => setShowSettings(false)} 
        currentSettings={settings}
        onSave={saveSettings}
      />
    </div>
  );
}

