        } else {
            // Fallback to local
            const local = JSON.parse(localStorage.getItem('chat_history') || '[]');
            setHistory(local);
        }
    } catch (e) {
        // Fallback
        const local = JSON.parse(localStorage.getItem('chat_history') || '[]');
        setHistory(local);
    }
  }, [settings.pythonBackendUrl]);

  useEffect(() => {
      fetchHistory();
